/* characters q02 (47 mục) — R2.6 bồi tiểu sử Đằng Lệ */
window.__LIBQ=window.__LIBQ||{};window.__LIBQ["tien-nghich"]=window.__LIBQ["tien-nghich"]||{};window.__LIBQ["tien-nghich"]["q02"]=window.__LIBQ["tien-nghich"]["q02"]||{};window.__LIBQ["tien-nghich"]["q02"]["characters"]={"updatedAt":"2026-07-12","count":47,"chars":[{"id":"bach-trien","name":"Bạch Triển","cn":"","aliases":["bạch y trung niên"],"gioiTinh":"nam","theLuc":["Tà đạo — đệ tử Tức Mặc lão nhân"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 15 đại viên mãn (@c0067)","trangThai":"tu-vong","vaiTro":"Phản diện giai đoạn Ch.67–68 / sư phụ cưỡng ép của Trương Hổ","tinhCach":"Tàn độc, lạnh lùng; tu tà đạo hút máu người để bổ thân; áp chế bằng áp lực tu vi","blurb":"Bạch y trung niên tu vi Ngưng Khí kỳ tầng 15 đại viên mãn, cảnh giới cao nhất của Ngưng Khí kỳ. Hắn hành ác bằng tà thuật hút máu, giết hại các thành viên đoàn tiêu để bổ thân. Cuối cùng bị Vương Lâm diệt trừ bằng ngọc phù Đan bảo, thân thể lẫn túi trữ vật đều hóa thành hư vô.","tabs":{"diem":[{"text":"Đạt Ngưng Khí kỳ tầng 15 đại viên mãn — tầng cao nhất của Ngưng Khí kỳ, xuất hiện với áp lực tu vi áp đả","chuong":"@c0067"},{"text":"Xuất hiện từ đám mây đen, giết các thành viên đoàn tiêu bằng tà thuật hút máu","chuong":"@c0067"},{"text":"Đại chiến với Vương Lâm, cuối cùng bị diệt bởi ngọc phù Đan bảo với chín phù văn vàng — thân thể và túi trữ vật hóa hư vô","chuong":"@c0068"}],"kinhLich":[{"chuong":"@c0067","importance":"major","text":"Xuất hiện từ đám mây đen, Ngưng Khí tầng 15 đại viên mãn. Giết các thành viên đoàn tiêu bằng tà thuật hút máu, đúc huyết châu. Tra tấn Trương Hổ trước mặt Vương Lâm. Phi kiếm có vỏ kiếm đen vô hiệu hóa Dẫn Lực Thuật của VL lần đầu tiên. (@c0067)"},{"chuong":"@c0068","importance":"major","text":"Tiếp tục đại chiến với Vương Lâm. Bị diệt bởi ngọc phù Đan bảo (9 phù văn vàng) — thân thể và túi trữ vật hóa tro bụi. VL thu phi kiếm cổ quái và vỏ kiếm đen. (@c0068)"}],"tuVi":"Ngưng Khí kỳ tầng 15 đại viên mãn — đỉnh Ngưng Khí kỳ (@c0067). Tà đạo hút máu. Chết @c0068.","tuViMoc":[{"chuong":"@c0067","canhGioi":"Ngưng Khí kỳ tầng 15 đại viên mãn","text":"Tầng cao nhất Ngưng Khí kỳ. Xuất hiện với áp lực tu vi áp đảo toàn bộ nhân vật khác trong trận."}],"nhanMach":[{"ten":"Tức Mặc lão nhân","quanHe":"Sư phụ","ghiChu":"Tán tu Kết Đan kỳ; Bạch Triển là đệ tử thứ sáu. Sau khi Bạch Triển chết, Tức Mặc lão nhân dự kiến sẽ điều tra @c0069.","tag":"su-mon"},{"ten":"Trương Hổ","quanHe":"Đệ tử (ép buộc)","ghiChu":"Khống chế bằng độc trùng ~4 năm; Trương Hổ thoát khỏi ràng buộc sau khi Bạch Triển chết @c0069.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0067","@c0068","@c0069"]},{"id":"tu-phi","name":"Từ Phi","cn":"","aliases":[],"gioiTinh":"nu","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 7 (@c0062); tầng 4 bốn năm trước khi Vương Lâm bế quan","trangThai":"song","vaiTro":"Nhân vật phụ — đệ tử Huyền Đạo Tông","tinhCach":"Từng có cảm tình với 'Vương Trác' (tức Vương Lâm giả danh); nhút nhát trước thần thức áp đảo của VL.","blurb":"Đệ tử Huyền Đạo Tông, tầng 7 Ngưng Khí. Họ 'Từ' của cô khiến Tư Đồ Nam (ẩn trong Nghịch Thiên Châu) bất ngờ. Từng có cảm tình với 'Vương Trác' là bí danh của Vương Lâm.","tabs":{"diem":[{"text":"Họ 'Từ' của cô gây phản ứng mạnh nơi Tư Đồ Nam ẩn trong Nghịch Thiên Châu.","chuong":"@c0063"}],"kinhLich":[{"chuong":"@c0062","importance":"minor","text":"Cùng Lịch Hải (Tam sư huynh) và tiểu sư đệ đến khu vực núi trọc nơi Vương Lâm đang bế quan. Tầng 7 Ngưng Khí (@c0062); trước đó 4 năm chỉ là tầng 4. Được miêu tả là từng có cảm tình với 'Vương Trác'. (@c0062)"},{"chuong":"@c0063","importance":"minor","text":"Cùng Lịch Hải bị thần thức của Vương Lâm áp chế, không dám động đậy. Họ 'Từ' của cô khiến Tư Đồ Nam (ký ký trong Nghịch Thiên Châu) bất ngờ ra mặt — hiếm khi Tư Đồ Nam phản ứng như vậy. Ba người được thả đi. (@c0063)"},{"text":"Là một trong hai người con cái Triệu, Từ ở bên Mộ Dung Trác dưới vực, Từ Phi kinh hãi trước chấn động, thầm nhủ Vương Lâm không phải kẻ có thể trêu chọc.","bridge":true,"khoang":"@c0594"}],"tuVi":"Ngưng Khí kỳ tầng 4 (4 năm trước @c0062) → tầng 7 (@c0062). Huyền Đạo Tông.","tuViMoc":[{"chuong":"@c0062","canhGioi":"Ngưng Khí kỳ tầng 7","text":"Tầng 7 tại thời điểm gặp Vương Lâm; tầng 4 bốn năm trước — tiến 3 tầng trong 4 năm."}],"nhanMach":[{"ten":"Lịch Hải","quanHe":"Tam sư huynh","ghiChu":"Đi cùng trong chuyến thăm núi trọc.","tag":"su-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0062","@c0063","@c0594"]},{"id":"lich-hai","name":"Lịch Hải","cn":"","aliases":["Tam sư huynh"],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng 12 (@c0063)","trangThai":"song","vaiTro":"Nhân vật phụ — đệ tử Huyền Đạo Tông","tinhCach":"Nhút nhát khi gặp nguy, ưu tiên bảo mạng; được gọi là 'Tam sư huynh' nên có vị trí trong môn phái.","blurb":"Đệ tử Huyền Đạo Tông, Ngưng Khí tầng 12. 'Tam sư huynh' của Từ Phi. Bị thần thức của Vương Lâm áp chế đến không dám nhúc nhích dù là tầng 12.","tabs":{"diem":[{"text":"Ngưng Khí tầng 12 nhưng bị thần thức (nhờ Nghịch Thiên Châu) của Vương Lâm áp đảo hoàn toàn — minh họa sức mạnh đặc dị của VL.","chuong":"@c0063"}],"kinhLich":[{"chuong":"@c0062","importance":"minor","text":"Đến khu vực núi trọc cùng Từ Phi và tiểu sư đệ. Được xác nhận tầng 12 Ngưng Khí, Tam sư huynh. (@c0062)"},{"chuong":"@c0063","importance":"minor","text":"Bị thần thức VL áp chế, quỳ xuống bất động cùng cả dã thú xung quanh. Không dám phản kháng. Ba người được thả sau khi VL nhận ra họ Từ của Từ Phi. (@c0063)"}],"tuVi":"Ngưng Khí kỳ tầng 12 (@c0063). Huyền Đạo Tông.","tuViMoc":[{"chuong":"@c0063","canhGioi":"Ngưng Khí kỳ tầng 12","text":"Tầng 12 xác nhận khi gặp Vương Lâm; Tam sư huynh trong nhóm."}],"nhanMach":[{"ten":"Từ Phi","quanHe":"Sư muội","ghiChu":"Đi cùng trong chuyến thăm núi trọc.","tag":"su-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0062","@c0063"]},{"id":"lieu-tam","name":"Liễu Tam","cn":"","aliases":["đại tiêu đầu Uy Vũ"],"gioiTinh":"nam","theLuc":["Uy Vũ tiêu cục"],"canhGioiCaoNhat":"Phàm nhân (võ sĩ — Khai Sơn chưởng lô hỏa thuần thanh @c0064)","trangThai":"song","vaiTro":"Nhân vật phụ — đại tiêu đầu tiêu cục","tinhCach":"Hào sảng, am hiểu giang hồ, biết người biết việc; có quan hệ rộng trong giới bất chính.","blurb":"Đại tiêu đầu Uy Vũ tiêu cục. Khai Sơn chưởng lô hỏa thuần thanh (võ công đỉnh phong người thường). Đã từng nghi Vương Lâm là gian tế nhưng chấp nhận hắn vào đội.","tabs":{"diem":[{"text":"Khai Sơn chưởng lô hỏa thuần thanh — võ công đỉnh phong nhân gian; hiểu biết rộng về giới tiêu cục và giang hồ.","chuong":"@c0064"}],"kinhLich":[{"chuong":"@c0064","importance":"minor","text":"Gặp Vương Lâm trên đường tới Thiên Thủy thành. Nghi VL là gian tế vì không có hành lý. Chấp nhận cho đi cùng sau khi VL bịa cớ 'bị cướp'. Dẫn đoàn tiêu hướng Thiên Thủy thành. (@c0064)"},{"chuong":"@c0066","importance":"minor","text":"Đặt hộp gấm (nhân sâm 500 năm) xuống đất khi đàm phán với 'Đại đương gia'; hộp bị VL hút mất bằng pháp lực. (@c0066)"}],"tuVi":"Phàm nhân — võ sĩ bậc cao (Khai Sơn chưởng lô hỏa thuần thanh). Không tu tiên.","tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0064","@c0066"]},{"id":"vuong-tien-sinh","name":"Vương tiên sinh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Uy Vũ tiêu cục"],"canhGioiCaoNhat":"Phàm nhân (tướng thuật có linh lực thật @c0065)","trangThai":"song","vaiTro":"Nhân vật phụ — thuật sĩ tướng số","tinhCach":"Nghiêm túc, có thực lực thật sự; uy tín nghề nghiệp khiến khi phun máu người ta tin đây là điềm thật.","blurb":"Thầy tướng của Uy Vũ tiêu cục có linh lực thật. Vương Lâm thấy qua thần thức tia linh lực trong mắt ông. Xem tướng Vương Lâm, phun máu và hét lên — hàm ý khí vận của VL vượt sức chịu đựng của thuật tướng.","tabs":{"diem":[{"text":"Thuật tướng có linh lực thật — Vương Lâm thấy qua thần thức tia linh lực chạy qua mắt ông khi xem tướng; không phải thuật sĩ lừa đảo.","chuong":"@c0065"},{"text":"Xem tướng Vương Lâm: phun máu, hét 'Ngươi—' rồi không hoàn thành câu — khí vận VL khủng khiếp ngoài sức tưởng tượng.","chuong":"@c0065"}],"kinhLich":[{"chuong":"@c0065","importance":"minor","text":"Được giới thiệu với Vương Lâm. Xem tướng VL — phun máu, hét lên 'Ngươi—' không nói được tiếp. Bị xóa ký ức về sự kiện @c0067 bởi Hóa Thần thuật của VL @c0069. (@c0065)"}],"tuVi":"Phàm nhân với linh lực tự nhiên — không phải tu sĩ, nhưng có năng lực tướng thuật thật sự (@c0065).","tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0065","@c0069"]},{"id":"dang-le","name":"Đằng Lệ","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Đằng Gia"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ (@c0072)","trangThai":"tu-vong","vaiTro":"Phản diện giai đoạn Ch.72 — cháu lão tổ Nguyên Anh Đằng Hóa Nguyên","tinhCach":"Ngạo mạn, tham lam quyết giết Vương Lâm để đoạt bảo bối thuấn di; có thực lực và kinh nghiệm chiến đấu đáng nể","blurb":"Đằng Lệ là tu sĩ Trúc Cơ hậu kỳ, cháu của lão tổ Nguyên Anh kỳ Đằng Hóa Nguyên. Y bày bẫy bắt Vương Lâm tại Đằng Gia Thành rồi truy sát suốt hơn năm ngày xuyên rừng, nhưng cuối cùng trúng mưu kế dây mây xanh của đối phương. Bị Vương Lâm bắt sống và luyện làm Lô Đỉnh cho Đoạt Cơ Đại Pháp, kết thúc với cái chết ở Chương 72.","tabs":{"diem":[{"text":"Tu vi Trúc Cơ hậu kỳ, cháu lão tổ Nguyên Anh kỳ Đằng Hóa Nguyên","chuong":"@c0072"},{"text":"Bày bẫy bắt Vương Lâm tại Đằng Gia Thành rồi truy sát hơn 5–6 ngày xuyên rừng","chuong":"@c0072"},{"text":"Trúng mưu kế dây mây xanh (Đằng Điều), bị bắt sống làm Lô Đỉnh cho Đoạt Cơ Đại Pháp","chuong":"@c0072"},{"text":"Được Vương Lâm nhắc lại trong hồi cố như một kẻ thù đã bị giết trong quá khứ","chuong":"@c1207"}],"kinhLich":[{"chuong":"@c0072","importance":"major","text":"Bày bẫy bắt Vương Lâm tại Đằng Gia Thành; truy sát hơn 5–6 ngày xuyên rừng. Bị mưu kế dây mây xanh (Đằng Điều) khiến nội giáp và pháp bảo hao mòn nghiêm trọng, buộc dùng nguyên bảo bảo mệnh của lão thái gia. Bị dụ vào tầm Thi Mị/Lục Đan tự bạo; Vương Lâm liều mạng dùng Lục Kiếm xuyên nội giáp + Tư Đồ Nam đóng băng bắt sống. Bị thi triển Đoạt Cơ Đại Pháp: thân thể luyện thành ba quả cầu máu/thịt/xương, linh hồn bị luyện hóa thành cầu tím, linh căn bị đoạt một phần ba. CHẾT. (@c0072)"}],"tuVi":"Trúc Cơ hậu kỳ (@c0072). Chết @c0072.","tuViMoc":[{"chuong":"@c0072","canhGioi":"Trúc Cơ hậu kỳ","text":"Xác nhận khi Tư Đồ Nam đánh giá lò đỉnh cho Đoạt Cơ Đại Pháp; bạn tri kỷ Trần Trung (đại đệ tử Tức Mặc Lão Nhân)."}],"nhanMach":[{"ten":"Đằng Hóa Nguyên","quanHe":"Ông nội (lão tổ Nguyên Anh kỳ)","ghiChu":"Lưu thần thức trong linh hồn Đằng Lệ; sau khi cháu chết, lập trận lời nguyền in lên Vương Lâm thề báo thù @c0072.","tag":"than-toc"},{"ten":"Vương Lâm","quanHe":"Kẻ thù / kẻ hạ sát","ghiChu":"Đằng Lệ truy sát, bị VL bắt sống, chết làm Lô Đỉnh @c0072.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0072"]},{"id":"dang-hoa-nguyen","name":"Đằng Hóa Nguyên","cn":"","aliases":["lão thái gia Đằng Gia","ông già mặc đồ đen"],"gioiTinh":"nam","theLuc":[{"ten":"Đằng Gia","trangThai":"da-roi"}],"canhGioiCaoNhat":"Nguyên Anh hậu kỳ (@c0210 — sau hơn 400 năm đã đạt cảnh giới thề nguyện); trước đó Nguyên Anh sơ kỳ @c0072, có hồn kỳ cấp Nguyên Anh @c0089","trangThai":"tu-vong","vaiTro":"Phản diện dài hạn — lão tổ Đằng Gia, truy thù Vương Lâm qua ba đời","tinhCach":"Yêu quý cháu và hạch tâm tộc nhân, bảo hộ gia tộc bằng mọi giá; báo thù quyết liệt, dai dẳng, không từ thủ đoạn; tàn nhẫn với huyết thân kẻ thù; đường cùng giả nhân nghĩa cầu sống","blurb":"Đằng Hóa Nguyên là lão tổ trấn giữ Đằng Gia — gia tộc tu chân đệ nhất Triệu quốc, ông nội Đằng Lệ. Khi phân thân thần thức cài trong linh hồn cháu cảm ứng được lúc Đằng Lệ bị luyện hóa, hắn lần theo trớ chú truy sát Vương Lâm, rồi diệt toàn bộ Vương gia hơn trăm người để thi hành lời nguyền. Sau hơn 400 năm bế quan đạt Nguyên Anh hậu kỳ, hắn vẫn không thoát được ngày Vương Lâm vây thành diệt tộc — cuối cùng bị giết, khép lại mối thù ba đời.","tabs":{"diem":[{"text":"Phân thân sương vàng xuất hiện khi Đằng Lệ bị luyện hóa, phát hiện Vương Lâm và mở đầu mối thù sinh tử","chuong":"@c0072"},{"text":"Đích thân diệt toàn bộ Vương gia hơn trăm người để thực hiện lời nguyền báo thù cho Đằng Lệ","chuong":"@c0087"},{"text":"Tại Quyết Minh Cốc, phóng Nguyên Anh ra ngoài xác, dùng trớ chú lưới máu giam chân Vương Lâm và lấy hồn phách phụ mẫu hắn phong trong Hồn Kỳ uy hiếp","chuong":"@c0100"},{"text":"Bế quan hơn 400 năm đạt Nguyên Anh hậu kỳ, trở thành lão tổ trấn giữ Đằng Gia thành — gia tộc tu chân đệ nhất Triệu quốc","chuong":"@c0210"},{"text":"Bị Vương Lâm vây thành chín ngày diệt tộc, giả ý xóa bỏ ân oán cầu tha mạng nhưng vẫn bị giết, mối thù ba đời kết thúc","chuong":"@c0222"}],"kinhLich":[{"chuong":"@c0072","importance":"major","text":"Hóa thân (phân thân sương vàng tầm xa) xuất hiện khi Đằng Lệ bị luyện hóa, do thần thức lưu trong linh hồn cháu kích hoạt. Hóa thân không có lực, chỉ truyền tiếng nói. Cảm nhận cháu chết, vỗ ngực phun máu đen lập trận lời nguyền phức tạp bằng máu + thần thức (hao tổn lớn Nguyên Anh); trận ngưng tụ đồ án hình thoi in lên trán Vương Lâm — là trận định vị, không công kích. (@c0072)"},{"chuong":"@c0077","importance":"major","text":"Theo trớ chú lần ra kẻ thù đang ở dưới đám cây cối, bầu trời tối sầm, hơi thở 'hủy thiên diệt địa'. Cảm nhận trong đám cây có 'thứ rất mạnh' nên dè dặt, cuối cùng vẫn cắn răng xông vào. (@c0077)"},{"chuong":"@c0078","importance":"major","text":"Tiếp cận Vương Lâm thì bị nam tử thây khô (Nguyên Anh trung kỳ) trong hắc vụ tấn công và quát đuổi. Dùng tấm da thú phòng thân độn thoát, bị bàn tay to sượt qua, phun một bụm máu, sắc mặt tái nhợt và bỏ chạy. (@c0078)"},{"chuong":"@c0087","importance":"major","text":"Đích thân tiêu diệt toàn bộ Vương gia (100+ người) để thực hiện lời nguyền báo thù Vương Lâm. Dùng hồn kỳ (pháp bảo Nguyên Anh kỳ) làm vũ khí. Sau khi xong việc đứng chờ bên ngoài Quyết Minh Cốc — kết đan+ bị phong ấn không vào trong được. (@c0087)","bridge":true},{"chuong":"@c0088","importance":"normal","text":"Vẫn chờ bên ngoài Quyết Minh Cốc. Nguyên nhân không vào được: đại trận phong ấn Kết Đan kỳ trở lên. (@c0088)"},{"chuong":"@c0089","importance":"normal","text":"Vẫn canh bên ngoài Quyết Minh Cốc chờ Vương Lâm ra. Tư Đồ Nam nhắc đến hồn kỳ trong tay Đằng Hóa Nguyên. (@c0089)"},{"chuong":"@c0096","importance":"normal","text":"Thông đạo Vực Ngoại mở; ĐHN hồi hộp phấn khích đứng chờ ở cốc khẩu cùng đám tu sĩ Triệu quốc — sắp được vào Vực Ngoại chiến trường. (@c0096)"},{"chuong":"@c0097","importance":"normal","text":"Linh giác cảm nhận trớ chú đang tiếp cận; thân phận khách khanh lão tổ Vô Phong Cốc được xác nhận. (@c0097)"},{"chuong":"@c0098","importance":"normal","text":"Bị VL giả Nguyên Anh trung kỳ công khai khiêu chiến trước đám đông; vươn tay chộp ngay, bị thuấn di né. Nhận ra VL dùng chiêu thuấn di — khả năng của Nguyên Anh kỳ trở lên, sinh nghi ngờ. (@c0098)"},{"chuong":"@c0099","importance":"normal","text":"Dùng Hồn Phiên (đại kỳ 7 thước, chứa 3 vạn tinh hồn) tấn công pháp bảo cự long A Ngốc. Nhận ra A Ngốc là nghi binh; mở kích hoạt Vực Ngoại thông đạo. (@c0099)"},{"chuong":"@c0100","importance":"major","text":"Phóng Nguyên Anh ra ngoài xác, dùng trớ chú lưới máu giam chân VL; lấy hồn phách phụ mẫu VL (phong trong Hồn Kỳ) tra tấn tinh thần. Hủy túi trữ vật VL kể cả lệnh bài tư cách. Bị VL tự chặt tay phải đoạt ngược túi trữ vật bằng Dẫn Lực Thuật. Cho ba vạn tinh hồn nuốt dần chân tay VL; bị sốc khi VL tự nổ thân thể phóng vào thông đạo Vực Ngoại; sắc mặt biến đổi, không kịp ngăn. (@c0100)"},{"chuong":"@c0101","importance":"normal","text":"Sau trận Quyết Minh Cốc, về Đằng Gia thành bế quan — thề không đạt Nguyên Anh hậu kỳ không xuất quan. Vẫn mang cảm giác sợ hãi sau khi đối đầu VL, không biết VL đã chết hay chưa. (@c0101)"},{"chuong":"@c0210","importance":"normal","text":"Hơn 400 năm sau, đã lên Nguyên Anh hậu kỳ và là lão tổ trấn giữ Đằng Gia thành — gia tộc tu chân đệ nhất Triệu quốc. Khi Vương Lâm trở về quê, trong lúc bế quan ông cảm nhận được huyết quang bất tường, dùng Dự linh thuật bói toán nhưng không dò ra tung tích Vương Lâm; lặng nhìn bài vị Đằng Lệ. (@c0210)"},{"chuong":"@c0211","importance":"normal","tieuDe":"VL vây thành 'chỉ vào không ra', triệu hồn phách Đằng Lệ định vị huyết thống","text":"Vương Lâm cố ý không giết hắn trước — cắm 16 trận kỳ vây Đằng gia thành chu vi ngàn dặm, dựng cấm chế 'chỉ vào không ra' nhốt toàn bộ tộc nhân. Triệu hồn phách Đằng Lệ để định vị chính xác từng người mang huyết thống Đằng gia trên toàn Triệu quốc — mục tiêu: cho ĐHN chứng kiến cả gia tộc bị diệt trước khi xử hắn sau cùng. (@c0211)"},{"chuong":"@c0212","importance":"major","text":"Nhận ra Vương Lâm qua bức họa do Đằng Tấn tìm được — người tóc bạc, mi tâm tinh điểm, cưỡi yêu thú kéo hàng trăm thi thể. Chấn động đến mức linh lực tự tiết ra ngoài, tan vỡ bàn ghế và vô tình giết chết vài con cháu đứng quá gần. Thốt lên 'Hóa ra là ngươi!' — ánh mắt Vương Lâm trước khi 'chết' 400 năm trước đã ám ảnh hắn suốt thời gian đó. Đích thân thử phá phong giới vạn dặm vây Đằng gia thành nhưng vô hiệu; mở toàn bộ trận pháp thành, bế quan giữ trạng thái đỉnh chờ quyết chiến. (@c0212)"},{"chuong":"@c0213","importance":"minor","text":"Không ra khỏi Đằng gia thành dù Hợp Hoan tông — nơi chứa hàng trăm tộc nhân Đằng gia — bị Vương Lâm tấn công. Giới tu sĩ Triệu quốc đồn hắn là 'Hóa Thần kỳ' do giết người chỉ bằng ánh nhìn. (@c0213)"},{"chuong":"@c0215","importance":"normal","tieuDe":"Cảm hơi thở Đằng Ngũ tắt, đối mặt VL lần đầu sau 400 năm","text":"Khi Đằng Ngũ — hạch tâm tộc nhân mà hắn yêu quý nhất sau Đằng Nhất vì giống Đằng Lệ — bị sương đen thôn hồn giết chỉ còn dưới 1000 dặm Đằng gia thành, ĐHN cảm nhận hơi thở hắn tắt, hóa tia chớp lao tới đối mặt Vương Lâm (màn sương đen tụ thành người) — lần đầu tiên sau 400 năm đứng trước mặt kẻ thù. (@c0215)"},{"chuong":"@c0216","importance":"major","text":"Đằng Hóa Nguyên (lão tổ Đằng gia) ở tầng cao nhất tổ ốc theo dõi 9 ngọc giản hạch tâm tộc nhân: 5 miếng đã vỡ trước đó, rồi miếng Đằng Tam (Đằng Hải — người hắn gọi là 「Hải nhi」) vỡ làm hai. Lần đầu tiên sau 400 năm rơi nước mắt — hai giọt. Điểm lại từng hạch tâm tộc nhân đã mất, trong đó Đằng Ngũ (gần giống Đằng Lệ nhất sau Đằng Nhất, được hắn yêu quý) cũng đã chết. Mơ hồ mang chút hối hận về việc năm xưa ép Đằng Tam chia lìa vợ phàm. Đằng gia lúc này đã 6/9 hạch tâm tộc nhân chết dưới tay VL. (@c0216)"},{"chuong":"@c0217","importance":"minor","text":"Mục tiêu tối hậu Vương Lâm quyết tiêu diệt sau cùng. Vương Lâm tuyên bố với Vương Trác: 'Đằng Hóa Nguyên không chạy được; cả họ Đằng không ai chạy được'. (@c0217)"},{"chuong":"@c0218","importance":"normal","tieuDe":"PNT tiết lộ hắn là 'chuột thí nghiệm'; 6/10 đốm sáng hạch tâm đã tắt","text":"Phác Nam Tử dò trên vách động thấy 10 đốm sáng vận mệnh hạch tâm tộc nhân — 6 đốm đã tắt. Tiết lộ: chính 'sứ giả đại nhân' bí ẩn đã chỉ định Đằng tộc làm đối tượng thí nghiệm; nhờ can thiệp đó Đằng gia mới có 9 Nguyên Anh tu sĩ và ĐHN tiến cảnh phi thường. Phác Nam Tử tuyên bố đây là lần cuối bảo hộ Đằng gia; ra tối hậu thư 100 năm phải có Hóa Thần kỳ. (@c0218)"},{"chuong":"@c0219","importance":"normal","tieuDe":"Cảm nhận Thông thiên thuật Cự Ma tộc toàn Triệu quốc","text":"Vương Lâm thi triển Thông thiên thuật Cự Ma tộc, hút 3/5 linh mạch Triệu quốc — toàn bộ Nguyên Anh tu sĩ trở lên tại Triệu quốc đều cảm nhận dị thường. ĐHN trong Đằng gia thành cũng không ngoại lệ. (@c0219)"},{"chuong":"@c0220","importance":"normal","text":"Đứng ở Đằng gia thành, tâm trạng ngày càng âm trầm khi thấy toàn bộ tộc nhân ùn ùn chạy về thành — bị cấm chế ngàn dặm 'chỉ vào không ra' của Vương Lâm vây kín, không ra ngoài ngăn cản được. Tin đồn kẻ thần bí tàn sát Đằng gia lan khắp thành; biết rõ Vương Lâm đang tiến tới. (@c0220)"},{"chuong":"@c0222","importance":"major","tieuDe":"Đằng Hóa Nguyên bị giết, mối thù ba đời kết thúc","text":"Cấm chế co rút, các chi nhánh Đằng gia xa gần đều diệt theo. ĐHN giả ý 'ân oán xóa bỏ' cầu tha mạng — VL nhìn thấu thật tâm chỉ muốn thoát thân để sau đạt Hóa Thần báo thù. Đúng lúc Phác Nam Tử giáng xuống, VL không ngần ngại phóng mũi nhọn ánh sáng xuyên mi tâm Đằng Hóa Nguyên — lão tổ Đằng gia chết tại chỗ. (@c0222); Trơ mắt nhìn toàn tộc Đằng gia bị diệt sạch; bị VL ép khai ra Cao Khải Minh (Phiêu Miểu Tông, dùng thuật bói toán) là kẻ năm xưa giúp tìm ra quê nhà họ Vương. Giả vờ 'ân oán xóa bỏ' khi nghĩ sẽ chết, nhưng nghe Phác Nam Tử tới ứng cứu thì bùng ý sống + thề đạt Hóa Thần báo thù — ngay khoảnh khắc đó bị VL bắn mũi nhọn ánh sáng xuyên mi tâm GIẾT CHẾT, chấm dứt huyết mạch Đằng gia."},{"chuong":"@c0221","importance":"major","text":"Ngày thứ chín VL diệt tộc Đằng gia: Đằng Hóa Nguyên cử bốn tu sĩ Nguyên Anh cuối cùng ra chặn đều bị giết dễ dàng; dùng cờ vàng triệu bộ xương khổng lồ phản kích nhưng bị VL áp chế bằng hồn kỳ; vô tình tự giết tộc nhân khi chia bộ xương thôn phệ linh hồn.; Bốn vị Nguyên Anh tu sĩ cuối cùng của Đằng gia bị hồn kỳ tàn diệt; ĐHN bị giam trong trận cấm, chứng kiến hơn nghìn thủ cấp tộc nhân bị xếp thành tháp đầu lâu trước cổng thành. Tuyệt vọng tung cờ vàng triệu binh cốt xương chống trả lần cuối; bị hồn kỳ đập tan. Bị ép khai ra Cao Khải Minh — chưởng môn Phiêu Miểu Tông — là người bói ra vị trí gia đình Vương Lâm. (@c0221)","nguonNblm":true}],"tuVi":"Nguyên Anh sơ kỳ (@c0072, yếu hơn Nguyên Anh trung kỳ @c0078). Sở hữu hồn kỳ cấp Nguyên Anh @c0089; bế quan thề Nguyên Anh hậu kỳ @c0101; sau hơn 400 năm đã đạt Nguyên Anh hậu kỳ @c0210.","tuViMoc":[{"chuong":"@c0072","canhGioi":"Nguyên Anh kỳ","text":"Xác nhận khi Đằng Lệ đe dọa 'ông nội là cao thủ Nguyên Anh kỳ' và hóa thân xuất hiện @c0072. Lập trận lời nguyền hao tổn lớn Nguyên Anh — Nguyên Anh rút nhỏ thấy rõ."},{"chuong":"@c0210","canhGioi":"Nguyên Anh hậu kỳ","text":"Sau hơn 400 năm tu luyện tại Đằng Gia thành, đạt Nguyên Anh hậu kỳ đúng như lời thề năm xưa."}],"nhanMach":[{"ten":"Đằng Lệ","quanHe":"Cháu nội","ghiChu":"Yêu quý đến mức lưu thần thức trong linh hồn cháu; cháu chết → thề báo thù Vương Lâm @c0072.","tag":"than-toc"},{"ten":"Vương Lâm","quanHe":"Kẻ thù (thề báo thù)","ghiChu":"Lời nguyền định vị in trên trán VL @c0072; truy sát @c0077; bị gián đoạn @c0078; diệt Vương gia @c0087; đang chờ VL ra @c0087–89; dùng hồn phách phụ mẫu tra tấn, bị VL tự nổ thân @c0100. Hơn 400 năm sau, VL trở về Triệu quốc lập thề diệt Đằng gia — ĐHN cảm huyết quang nhưng bói không ra @c0210.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0072","@c0077","@c0078","@c0087","@c0088","@c0089","@c0096","@c0097","@c0098","@c0099","@c0100","@c0101","@c0210","@c0211","@c0212","@c0213","@c0215","@c0216","@c0217","@c0218","@c0219","@c0220","@c0221","@c0222"]},{"id":"a-ngoc","name":"A Ngốc","cn":"","aliases":["a Mộc","quái nhân da lam"],"gioiTinh":"nam","theLuc":["Thi Âm tông (liên hệ Ngô Vũ)"],"canhGioiCaoNhat":"Nguyên Anh trung kỳ tiềm ẩn (do nửa tinh khí Nguyên Anh Ngô Vũ để lại @c0079)","trangThai":"song","vaiTro":"Thi khôi cũ Ngô Vũ hồi sinh, đồng hành Vương Lâm","tinhCach":"Trí tuệ như trẻ thơ, chỉ thốt từng chữ ('Kính', 'Cực'); bản năng chiến đấu cực mạnh; nhe răng dọa người; thân thiết nương tựa Ngô Vũ","blurb":"Quái nhân da lam khắc đầy ký hiệu cổ quái, mang chín tấm phù vàng — mỗi tấm kéo xuống tăng gấp đôi thực lực và trị thương tức thì. Thực chất là thi khôi cũ của Ngô Vũ, người từng định đoạt xá nhưng thất bại vì 'lực lượng hủy thiên diệt địa' trong cơ thể hắn; Ngô Vũ để lại nửa tinh khí Nguyên Anh trung kỳ khiến hắn tỉnh dậy với tiềm năng khổng lồ. Sau khi cùng Vương Lâm vào Thi Âm tông, hắn bị Dạ Tự Tại nhận làm lô đỉnh và trở thành đối tượng trong kế hoạch nâng lên Kết Đan kỳ của La Sát.","tabs":{"diem":[{"text":"Sinh vật da lam cắn nuốt thi thể quái thú, bị khí âm hàn của Vương Lâm thu hút","chuong":"@c0077"},{"text":"Thử sức với Vương Lâm: kéo phù vàng, dùng quyền pháp ẩn lực đạo cổ quái đẩy lùi VL ba thước","chuong":"@c0079"},{"text":"Thi khôi Nguyên Anh trung kỳ tiềm ẩn — Ngô Vũ xác nhận là thi khôi cũ của mình, để lại nửa tinh khí","chuong":"@c0079"},{"text":"Cùng Vương Lâm xuất hiện tại truyền tống trận Thi Âm tông, khiến tám đệ tử gác trận kinh ngạc vì linh tính dồi dào","chuong":"@c0080"},{"text":"Bị Dạ Tự Tại nhận làm lô đỉnh (thi khôi giả đan); La Sát lập kế hoạch nâng lên Kết Đan kỳ","chuong":"@c0081"},{"text":"Ở lại Thi Âm tông dưới kế hoạch của La Sát khi Vương Lâm bị gửi đến Quyết Minh Cốc","chuong":"@c0086"}],"kinhLich":[{"chuong":"@c0077","importance":"minor","text":"Sinh vật da lam đang cắn nuốt thi thể quái thú trong đống đổ nát; bị hiện tượng hút khí âm hàn của Vương Lâm làm sợ hãi, định lại gần nhưng dừng ở cách ~3000 trượng. (@c0077)"},{"chuong":"@c0078","importance":"minor","text":"Lảng vảng quan sát Vương Lâm với vẻ chần chừ; cuối chương lao tới chỗ VL như tia chớp. (@c0078)"},{"chuong":"@c0079","importance":"major","text":"Thử sức với Vương Lâm: kéo phù vàng xuống, dùng quyền pháp ẩn lực đạo cổ quái khiến VL lùi ba thước. Dẫn VL đến pho tượng nam tử cự long (4 ngày đường), mở 8 viên thạch châu kích hoạt pho tượng. Cứu VL khỏi vòng sáng khi thi khôi nam tử thây khô tới, kéo VL vào bên trong pho tượng. Do dự rồi theo VL lao vào truyền tống trận tới Thi Âm tông. (@c0079)"},{"chuong":"@c0080","importance":"normal","text":"Cùng VL xuất hiện trong truyền tống trận Thi Âm tông; khiến tám đệ tử gác trận kinh ngạc vì linh tính dồi dào. Được Mộc Ngung và thanh niên gác trận nhận xét chỉ thấp hơn Phi Thiên La Sát. Nhe răng dọa thanh niên gác trận khi bị nhìn lâu. (@c0080)"},{"chuong":"@c0081","importance":"normal","text":"Dạ Tự Tại nhận a Ngốc làm lô đỉnh (thi khôi giả đan); La Sát có kế hoạch nâng a Ngốc lên Kết Đan kỳ bằng nghi thức giả đan. (@c0081)"},{"chuong":"@c0082","importance":"minor","text":"Vẫn ở Thi Âm tông dưới sự giám sát của Dạ Tự Tại / La Sát. (@c0082)"},{"chuong":"@c0086","importance":"normal","text":"La Sát vẫn giữ kế hoạch nâng a Ngốc lên Kết Đan. A Ngốc ở lại Thi Âm tông khi VL bị gửi đến Quyết Minh Cốc cùng 20 vật dẫn. (@c0086)"}],"tuVi":"Thi khôi với lực lượng hủy thiên diệt địa (nửa tinh khí Nguyên Anh trung kỳ Ngô Vũ); quyền pháp ẩn lực đạo cổ quái 'không phải linh lực' (@c0079). Mục tiêu: nâng lên Kết Đan kỳ bởi La Sát @c0081–@c0086.","tuViMoc":[{"chuong":"@c0079","canhGioi":"Thi khôi Nguyên Anh trung kỳ tiềm ẩn","text":"Ngô Vũ xác nhận đây là thi khôi cũ của mình; nửa tinh khí Nguyên Anh trung kỳ trong cơ thể khiến Ngô Vũ không đoạt xá được ('lực lượng hủy thiên diệt địa')."}],"nhanMach":[{"ten":"Ngô Vũ","quanHe":"Chủ nhân cũ (đoạt xá thất bại)","ghiChu":"Ngô Vũ để lại nửa tinh khí Nguyên Anh trong thân a Ngốc → tỉnh dậy sinh cảm giác thân thiết với Ngô Vũ @c0079.","tag":"dong-hanh"},{"ten":"Vương Lâm","quanHe":"Đồng hành (từ @c0079)","ghiChu":"VL thực chất đang 'sở hữu' a Ngốc dù không chính thức tế luyện.","tag":"dong-hanh"},{"ten":"Dạ Tự Tại / La Sát","quanHe":"Chủ nhân hiện tại (kế hoạch lô đỉnh giả đan)","ghiChu":"Bị nhận làm lô đỉnh thi khôi giả đan @c0081; La Sát kế hoạch nâng a Ngốc lên Kết Đan.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0077","@c0078","@c0079","@c0080","@c0081","@c0082","@c0086"]},{"id":"ngo-vu","name":"Ngô Vũ","cn":"","aliases":["lão tổ Ngô Vũ","người đồng tử cao một thước"],"gioiTinh":"nam","theLuc":["Thi Âm tông"],"canhGioiCaoNhat":"Nguyên Anh kỳ (suy yếu sau mấy trăm năm) (@c0079)","trangThai":"song (ẩn trong pho tượng đá)","vaiTro":"Lão tổ Thi Âm tông bị mắc kẹt; nhờ Vương Lâm tìm Dạ Tự Tại","tinhCach":"Thận trọng, khôn ngoan khi yếu thế; lấy Nguyên Anh ra thề để trấn an người khác; lai lịch phức tạp, có thể chưa nói hết sự thật","blurb":"Lão tổ Thi Âm tông, sư huynh của Dạ Tự Tại. Ba trăm năm trước mang thi khôi (a Ngốc) tới Hoàng Âm chi địa định đột phá Nguyên Anh nhưng thất bại; thi khôi thoát khống chế, đắc cơ duyên đột phá Nguyên Anh trung kỳ. Ngô Vũ buộc phải để Nguyên Anh ly thể ẩn vào pho tượng đá, bị thân thể cũ (nay là nam tử thây khô) truy sát suốt mấy trăm năm, rồi nhờ Vương Lâm tìm Dạ Tự Tại cứu mình.","tabs":{"diem":[{"text":"Lão tổ Thi Âm tông, sư huynh của Dạ Tự Tại; từng tu tới Nguyên Anh kỳ nhưng nay suy yếu","chuong":"@c0079"},{"text":"Nguyên Anh ly thể, ẩn thân trong pho tượng đá dưới dạng người đồng tử cao chừng một thước, thần thái suy yếu","chuong":"@c0079"},{"text":"Ba trăm năm trước mang thi khôi (a Ngốc) tới Hoàng Âm chi địa định đột phá Nguyên Anh nhưng thất bại; thi khôi thoát khống chế đắc cơ duyên đột phá Nguyên Anh trung kỳ","chuong":"@c0079"},{"text":"Bị thân thể cũ (nam tử thây khô) truy sát suốt mấy trăm năm, phải nhờ Vương Lâm tìm Dạ Tự Tại cứu","chuong":"@c0079"},{"text":"Là cơ sở danh nghĩa để Vương Lâm được Dạ Tự Tại nhận làm đại đệ tử thứ hai","chuong":"@c0081"}],"kinhLich":[{"chuong":"@c0079","importance":"major","text":"Hiện ra dưới dạng người đồng tử cao một thước, thần thái suy yếu, ánh sáng ảm đạm trong pho tượng đá. Kể lai lịch (ba trăm năm bị thân thể cũ truy sát, ẩn trong pho tượng). Lấy Nguyên Anh ra thề không lừa dối. Khẩn cầu VL tìm sư huynh Dạ Tự Tại. Mở truyền tống trận hình ngũ giác vàng đưa VL + a Ngốc về Thi Âm tông. (@c0079)"},{"chuong":"@c0081","importance":"minor","text":"Được nhắc đến gián tiếp: VL được Dạ Tự Tại nhận là đại đệ tử thứ hai — qua đó Ngô Vũ là cơ sở danh nghĩa để VL vào Thi Âm tông. (@c0081)"},{"chuong":"@c0086","importance":"minor","text":"Vẫn trong pho tượng đá — được nhắc gián tiếp khi La Sát quyết định cử VL (đại đệ tử thứ hai) đến Quyết Minh Cốc. (@c0086)"}],"tuVi":"Nguyên Anh kỳ, suy yếu sau mấy trăm năm (chỉ còn Nguyên Anh thể cao một thước @c0079).","tuViMoc":[{"chuong":"@c0079","canhGioi":"Nguyên Anh kỳ (suy yếu)","text":"Nguyên Anh li thể ẩn trong pho tượng đá; chỉ cao chừng một thước (suy yếu sau mấy trăm năm hao tổn)."}],"nhanMach":[{"ten":"Dạ Tự Tại","quanHe":"Sư huynh Thi Âm tông","ghiChu":"Ngô Vũ nhờ VL tìm sư huynh cứu mình @c0079.","tag":"su-mon"},{"ten":"A Ngốc","quanHe":"Thi khôi cũ (đoạt xá thất bại)","ghiChu":"Để lại nửa tinh khí Nguyên Anh trong thân a Ngốc @c0079.","tag":"dong-hanh"},{"ten":"Vương Lâm","quanHe":"Người được nhờ cứu","ghiChu":"Khắc bí thuật lên lưng VL để VL danh chính ngôn thuận vào Thi Âm tông @c0079.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0079","@c0081","@c0086"]},{"id":"moc-ngung","name":"Mộc Ngung","cn":"","aliases":["Mộc Nhũng","chấp sự trưởng lão"],"gioiTinh":"nam","theLuc":["Thi Âm tông"],"canhGioiCaoNhat":"Trúc Cơ trung kỳ (@c0080)","trangThai":"song","vaiTro":"Chấp sự trưởng lão Thi Âm tông Triệu quốc, Trúc Cơ trung kỳ","tinhCach":"Thực dụng, biết nhìn thực lực; cung kính lập tức khi nghe tên Ngô Vũ; tận tụy phụng sự cấp trên trong tông","blurb":"Mộc Ngung là chấp sự trưởng lão Thi Âm tông Triệu quốc, tu vi Trúc Cơ trung kỳ, tu luyện bằng cách hấp thụ khí xanh biếc từ hỏa cầu Lam Viêm Ma hỏa. Nhân vật tiếp đón Vương Lâm, gọi 'sư thúc về tông' khi nghe tên Ngô Vũ, rồi dùng ngọc giản liên lạc Dạ Tự Tại lão tổ. Về sau còn dẫn Vương Lâm xuống Địa Âm chi địa để tu luyện và chứng kiến việc Vương Lâm được nhận làm đại đệ tử thứ hai.","tabs":{"diem":[{"text":"Chấp sự trưởng lão Thi Âm tông, tu vi Trúc Cơ trung kỳ (đột phá ba năm trước)","chuong":"@c0081"},{"text":"Tu luyện bằng cách hấp thụ khí xanh biếc từ hỏa cầu Lam Viêm Ma hỏa qua thất khiếu trong huyệt động cột đá","chuong":"@c0080"},{"text":"Tiếp đón Vương Lâm và dùng ngọc giản liên lạc gọi Dạ Tự Tại lão tổ","chuong":"@c0080"},{"text":"Chứng kiến Vương Lâm được Dạ Tự Tại chính thức nhận làm đại đệ tử thứ hai","chuong":"@c0081"},{"text":"Dẫn Vương Lâm xuống Địa Âm chi địa — huyệt động âm hàn sâu nhất của tông — để tu luyện Hoàng Tuyền Thăng Khiếu","chuong":"@c0084"},{"text":"Chứng kiến La Sát (qua thân Dạ Tự Tại) cử Vương Lâm đi Quyết Minh Cốc cùng nhóm vật dẫn do Đổ Trần dẫn đường","chuong":"@c0086"}],"kinhLich":[{"chuong":"@c0080","importance":"major","text":"Đang ngồi tu luyện hấp thụ Lam Viêm Ma hỏa trong huyệt động cột đá; tiếp đón Vương Lâm do thanh niên gác trận dẫn tới. Khi nghe VL xưng đệ tử Ngô Vũ lập tức đứng bật dậy, xưng mình là Mộc Ngung, gọi VL là 'sư thúc'. Dùng ngọc giản liên lạc Dạ lão tổ. Khen kỹ thuật 'ngưng khói thành thật' của VL — tia hoài nghi cuối cùng bị triệt tiêu. Quỳ rạp khi Dạ Tự Tại xuất hiện cuối chương. (@c0080)"},{"chuong":"@c0081","importance":"minor","text":"Chứng kiến VL được Dạ Tự Tại chính thức nhận làm đại đệ tử thứ hai. Xác nhận bản thân đã đột phá ba năm trước. (@c0081)"},{"chuong":"@c0084","importance":"minor","text":"Dẫn VL xuống Địa Âm chi địa (huyệt động âm hàn sâu nhất của Thi Âm tông) để VL tu luyện Hoàng Tuyền Thăng Khiếu Quyết. (@c0084)"},{"chuong":"@c0086","importance":"minor","text":"Chứng kiến La Sát (qua thân Dạ Tự Tại) cử VL đi Quyết Minh Cốc cùng nhóm 20 vật dẫn dẫn đường bởi Đổ Trần. (@c0086)"}],"tuVi":"Trúc Cơ trung kỳ (@c0080). Đột phá ba năm trước @c0081.","tuViMoc":[{"chuong":"@c0080","canhGioi":"Trúc Cơ trung kỳ","text":"VL đảo thần thức xác định Mộc Ngung Trúc Cơ trung kỳ khi gặp mặt @c0080."}],"nhanMach":[{"ten":"Dạ Tự Tại","quanHe":"Lão tổ cấp trên","ghiChu":"Quỳ rạp khi Dạ Tự Tại xuất hiện; liên lạc qua ngọc giản @c0080.","tag":"su-mon"},{"ten":"Vương Lâm","quanHe":"Khách/sư thúc (giả)","ghiChu":"Gọi VL là 'sư thúc' khi biết VL là đệ tử Ngô Vũ @c0080; dẫn VL xuống Địa Âm chi địa @c0084.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0080","@c0081","@c0084","@c0086"]},{"id":"da-tu-tai","name":"Dạ Tự Tại","cn":"","aliases":["Dạ lão tổ"],"gioiTinh":"nam","theLuc":["Thi Âm tông"],"canhGioiCaoNhat":"Nguyên Anh kỳ (@c0079–@c0080); thọ mệnh còn <3 tháng @c0081","trangThai":"song (thân thể do La Sát ký sinh điều khiển; thọ mệnh cực ngắn @c0081)","vaiTro":"Lão tổ tối cao Thi Âm tông Triệu quốc (thân xác bị La Sát ký sinh)","tinhCach":"Uy áp khổng lồ khiến cả tông quỳ bái; giọng lạnh lẽo khi thẩm vấn Vương Lâm; giữ tình nghĩa sư môn với Ngô Vũ; sau @c0081 thân xác thực chất do La Sát điều khiển","blurb":"Dạ Tự Tại, bí danh Dạ lão tổ, là lão tổ tối cao của Thi Âm tông Triệu quốc, tu vi Nguyên Anh kỳ suy ra từ uy áp và quy chế trận pháp (41+ đạo ánh sáng đại biểu Nguyên Anh lão tổ). Ông sở hữu Phi Thiên La Sát và tế luyện Lam Viêm Ma hỏa, nhận Vương Lâm làm đại đệ tử thứ hai và truyền dạy Hoàng Tuyền Đạo. Từ @c0081, thân thể ông thực chất bị La Sát — một ký sinh hữu tri cổ xưa — kiểm soát, thọ mệnh chỉ còn dưới ba tháng.","tabs":{"diem":[{"text":"Lão tổ tối cao Thi Âm tông Triệu quốc, tu vi Nguyên Anh kỳ suy ra từ quy chế trận pháp 41+ đạo ánh sáng","chuong":"@c0080"},{"text":"Xuất hiện dưới dạng bóng người hư ảo từ bốn hỏa cầu Lam Viêm Ma hỏa, chất vấn Vương Lâm","chuong":"@c0080"},{"text":"Chính thức nhận Vương Lâm làm đại đệ tử thứ hai và trao ngọc giản lam đậm Thi Âm tông","chuong":"@c0081"},{"text":"Thân thể bị La Sát — ký sinh hữu tri cổ xưa — kiểm soát, thọ mệnh còn dưới ba tháng","chuong":"@c0081"},{"text":"Truyền dạy Vương Lâm công pháp cốt lõi Hoàng Tuyền Đạo trong huyệt động","chuong":"@c0082"},{"text":"La Sát qua thân Dạ Tự Tại cử Vương Lâm đến Quyết Minh Cốc cùng 20 vật dẫn dưới sự dẫn dắt của Đổ Trần","chuong":"@c0086"}],"kinhLich":[{"chuong":"@c0079","importance":"minor","text":"Ngô Vũ nhắc đến Dạ Tự Tại là sư huynh tại Thi Âm tông, nhờ Vương Lâm tìm để cứu mình. (@c0079)"},{"chuong":"@c0080","importance":"major","text":"Được Mộc Ngung liên lạc qua ngọc giản. Xuất hiện dưới dạng bóng người hư ảo từ bốn hỏa cầu Lam Viêm Ma hỏa tối sầm tỏa khói xanh; uy áp khổng lồ khiến Mộc Ngung quỳ rạp, Vương Lâm sợ hãi. Cất giọng lạnh lẽo hỏi 'Ngươi chính là đệ tử của Ngô Vũ sư đệ?' — chương dừng tại đây. (@c0080)"},{"chuong":"@c0081","importance":"major","text":"Chính thức nhận VL làm đại đệ tử thứ hai, trao cho VL ngọc giản lam đậm Thi Âm tông. Tiết lộ thân thể đã bị La Sát ký sinh hoàn toàn, thọ mệnh còn dưới 3 tháng. Nhận a Ngốc làm lô đỉnh thi khôi giả đan, với kế hoạch dùng VL cùng 20 người làm vật dẫn nâng thi khôi giả đan lên Kết Đan kỳ. (@c0081)","bridge":true},{"chuong":"@c0082","importance":"normal","text":"Giới thiệu VL về Hoàng Tuyền Đạo (công pháp cốt lõi Thi Âm tông); hướng dẫn VL luyện tập trong huyệt động Địa Âm chi địa. (@c0082)"},{"chuong":"@c0086","importance":"major","text":"La Sát (qua thân Dạ Tự Tại) quyết định cử VL đến Quyết Minh Cốc cùng 20 vật dẫn, dưới sự dẫn dắt của Đổ Trần (Trúc Cơ hậu kỳ, có giả đan). (@c0086)"},{"chuong":"@c0142","importance":"minor","text":"Tái xuất hiện dưới dạng một hồn cộng sinh trong thân Triệu Truyện Lương (tông chủ chi nhánh Thi Âm tông tại Hỏa Phần quốc); tự xưng từng làm tông chủ Thi Âm tông Triệu quốc, thân thể tuyệt hảo từng bị ngũ cấp tông cưỡng đoạt nên chưa khôi phục được tu vi. Giọng lạnh lùng, không cam lòng. (@c0142)"}],"tuVi":"Nguyên Anh kỳ (@c0079–@c0080). Thân thể bị La Sát ký sinh; thọ mệnh <3 tháng @c0081. Sở hữu Phi Thiên La Sát và Lam Viêm Ma hỏa (tế luyện từ kim đan cao thủ Kết Đan kỳ Chánh Đạo Liên Minh).","tuViMoc":[{"chuong":"@c0080","canhGioi":"Nguyên Anh kỳ","text":"Suy ra từ: quy chế trận pháp (41+ đạo ánh sáng = địa vị Nguyên Anh lão tổ); uy áp khổng lồ khiến Trúc Cơ trung kỳ quỳ rạp và Trúc Cơ trung kỳ VL sợ hãi @c0080."}],"nhanMach":[{"ten":"Ngô Vũ","quanHe":"Sư huynh (tại Thi Âm tông)","ghiChu":"Dạ Tự Tại gọi 'Ngô Vũ sư đệ' @c0080; Ngô Vũ nhờ VL tìm Dạ Tự Tại cứu mình @c0079.","tag":"su-mon"},{"ten":"Vương Lâm","quanHe":"Đại đệ tử thứ hai (danh nghĩa); vật dẫn (thực chất)","ghiChu":"Nhận VL làm đệ tử @c0081; cử VL đến Quyết Minh Cốc @c0086. Thực chất La Sát dùng VL làm vật dẫn nâng thi khôi giả đan.","tag":"su-mon"},{"ten":"La Sát","quanHe":"Ký sinh kiểm soát thân thể","ghiChu":"La Sát là ký sinh hữu tri cổ xưa hoàn toàn kiểm soát Dạ Tự Tại từ nội tâm @c0081.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0079","@c0080","@c0081","@c0082","@c0086","@c0142"]},{"id":"nam-tu-thay-kho","name":"Nam tử thây khô","cn":"","aliases":["thi khôi Ngô Vũ","thi mị Nguyên Anh trung kỳ","thân thể cũ Ngô Vũ"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Nguyên Anh trung kỳ (@c0078–@c0079)","trangThai":"song (truy sát Ngô Vũ)","vaiTro":"Thân thể cũ của lão tổ Ngô Vũ, tự sinh thần trí, truy sát Ngô Vũ để đoạt tự do","tinhCach":"Lạnh lùng, kiên nhẫn; dùng cổ ngữ điều khiển pho tượng; không truy đuổi Đằng Hóa Nguyên sau khi đánh đuổi","blurb":"Thân thể cũ của lão tổ Ngô Vũ, ba trăm năm trước bị Ngô Vũ bỏ lại khi Nguyên Anh ly thể chạy thoát; thân thể nảy sinh thần trí và đắc cơ duyên đột phá Nguyên Anh trung kỳ, vượt qua chính Ngô Vũ. Bị ràng buộc không được rời Ngô Vũ quá trăm dặm nếu không sẽ tan, và mỗi lần hoạt động phải nghỉ khoảng trăm năm. Xuất hiện truy sát Ngô Vũ: đánh đuổi Đằng Hóa Nguyên rồi phá pho tượng để tìm chủ nhân, nhưng để Ngô Vũ cùng đồng hành kịp truyền tống đi.","tabs":{"diem":[{"text":"Đột phá Nguyên Anh trung kỳ, vượt qua tu vi của Ngô Vũ nguyên chủ","chuong":"@c0078"},{"text":"Hiện ra từ làn hắc vụ, dùng cánh tay khô héo hóa bàn tay to và phong ấn không gian đánh đuổi Đằng Hóa Nguyên","chuong":"@c0078"},{"text":"Gián tiếp ra tay từ quan tài, ngưng tụ lôi cầu tím bằng hắc quang và tuyên bố kỳ hạn trăm năm","chuong":"@c0077"},{"text":"Nói cổ ngữ ngăn pho tượng chui xuống đất, phá pho tượng để truy tìm Ngô Vũ","chuong":"@c0079"}],"kinhLich":[{"chuong":"@c0077","importance":"normal","text":"Xuất hiện gián tiếp: bàn tay khô héo lóe hắc quang ngưng tụ lôi cầu tím từ quan tài hở góc; nói 'kỳ hạn trăm năm sắp tới — chủ nhân của ta, ngươi không chạy thoát được nữa đâu'. (@c0077)"},{"chuong":"@c0078","importance":"major","text":"Hiện ra từ làn hắc vụ, đánh đuổi Đằng Hóa Nguyên (dùng cánh tay khô héo hóa bàn tay to + phong ấn không gian); bắt thi mị ép tìm Nguyên Anh của chủ nhân (Ngô Vũ). (@c0078)"},{"chuong":"@c0079","importance":"major","text":"Từ quan tài bay tới, nói cổ ngữ ngăn pho tượng chui xuống đất; tuyên bố 'Chủ nhân! Lần này xem ngươi chạy trốn đi đâu.' Phá vỡ pho tượng nhưng để Ngô Vũ + VL + a Ngốc kịp truyền tống đi. (@c0079)"}],"tuVi":"Nguyên Anh trung kỳ (@c0078). Mạnh hơn Nguyên Anh kỳ Đằng Hóa Nguyên.","tuViMoc":[{"chuong":"@c0078","canhGioi":"Nguyên Anh trung kỳ","text":"Đằng Hóa Nguyên đảo thần thức phát hiện tu vi đối phương là Nguyên Anh trung kỳ — cảnh giới lão không thể chống lại @c0078."}],"nhanMach":[{"ten":"Ngô Vũ","quanHe":"Chủ nhân cũ (đang truy sát để nuốt Nguyên Anh)","ghiChu":"Thân thể cũ Ngô Vũ; truy sát để chiếm Nguyên Anh → đoạt tự do @c0079.","tag":"doi-thu"},{"ten":"Đằng Hóa Nguyên","quanHe":"Bị đánh đuổi @c0078","ghiChu":"Đánh thương ĐHN, không đuổi theo sau khi lão bỏ chạy.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0077","@c0078","@c0079"]},{"id":"la-sat","name":"La Sát","cn":"","aliases":["ký sinh trong Dạ Tự Tại"],"gioiTinh":"nam","theLuc":["Thi Âm tông (qua thân Dạ Tự Tại)"],"canhGioiCaoNhat":"Không rõ (cổ xưa, hữu tri — ký sinh trong Nguyên Anh kỳ tu sĩ @c0081)","trangThai":"song (ký sinh trong thân xác Dạ Tự Tại)","vaiTro":"Thực thể bí ẩn ký sinh, kiểm soát Thi Âm tông từ bóng tối","tinhCach":"Lạnh lùng, tính toán dài hạn; dùng người làm công cụ/vật dẫn; kiên trì với kế hoạch đã định","blurb":"La Sát là ký sinh hữu tri cổ xưa đang chiếm thân xác Dạ Tự Tại, lão tổ Nguyên Anh kỳ của Thi Âm tông, với thọ mệnh của vật chủ chỉ còn dưới ba tháng. Từ trong bóng tối, hắn điều khiển tông môn và triển khai kế hoạch dùng người làm vật dẫn nhằm nâng cấp thi khôi cùng thân phận của mình.","tabs":{"diem":[{"text":"Là ký sinh hữu tri cổ xưa, chiếm thân Dạ Tự Tại (Nguyên Anh kỳ) với thọ mệnh vật chủ còn dưới ba tháng","chuong":"@c0081"},{"text":"Sở hữu Phi Thiên La Sát, pháp bảo đỉnh cấp thi khôi","chuong":"@c0081"},{"text":"Hoạch định dùng VL cùng 20 người làm vật dẫn để nâng thi khôi giả đan lên Kết Đan","chuong":"@c0081"},{"text":"Cử VL đến Quyết Minh Cốc cùng 20 vật dẫn, dẫn đường bởi Đổ Trần (Trúc Cơ hậu kỳ có giả đan)","chuong":"@c0086"}],"kinhLich":[{"chuong":"@c0081","importance":"major","text":"Bản chất thật tiết lộ: La Sát là ký sinh hữu tri cổ xưa trong thân Dạ Tự Tại. Thọ mệnh Dạ Tự Tại <3 tháng. Nhận VL làm đại đệ tử thứ hai; nhận a Ngốc làm lô đỉnh thi khôi giả đan. Kế hoạch: VL + 20 người làm vật dẫn nâng thi khôi giả đan. Trao ngọc giản Thi Âm tông cho VL. (@c0081)","bridge":true},{"chuong":"@c0086","importance":"major","text":"Cử VL đến Quyết Minh Cốc cùng 20 vật dẫn, dẫn đường bởi Đổ Trần (Trúc Cơ hậu kỳ có giả đan). Vẫn giữ kế hoạch nâng a Ngốc lên Kết Đan kỳ. (@c0086)"}],"tuVi":"Không rõ (cổ xưa, hữu tri); đang ký sinh Nguyên Anh kỳ tu sĩ @c0081.","tuViMoc":[],"nhanMach":[{"ten":"Dạ Tự Tại","quanHe":"Vật chủ ký sinh","ghiChu":"Chiếm thân xác Dạ Tự Tại; Dạ Tự Tại thọ mệnh <3 tháng @c0081.","tag":"doi-thu"},{"ten":"Vương Lâm","quanHe":"Vật dẫn / đại đệ tử thứ hai (danh nghĩa)","ghiChu":"Dùng VL làm vật dẫn nâng thi khôi giả đan @c0081; cử VL đến Quyết Minh Cốc @c0086.","tag":"doi-thu"},{"ten":"A Ngốc","quanHe":"Lô đỉnh thi khôi (kế hoạch)","ghiChu":"Kế hoạch nâng a Ngốc lên Kết Đan kỳ @c0081–@c0086.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0081","@c0086"]},{"id":"do-tran","name":"Đổ Trần","cn":"","aliases":["Đỗ Trần"],"gioiTinh":"nam","theLuc":["Thi Âm tông"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ, có giả đan (@c0086)","trangThai":"song","vaiTro":"Đệ tử cao cấp Thi Âm tông — dẫn đường nhóm vật dẫn vào Quyết Minh Cốc","tinhCach":"Phục lệnh La Sát; thực dụng; không biểu lộ cảm xúc với vật dẫn đi cùng","blurb":"Đổ Trần là đệ tử cao cấp Thi Âm tông, tu vi Trúc Cơ hậu kỳ có giả đan. Được La Sát (qua thân Dạ Tự Tại) phái dẫn nhóm 20 vật dẫn cùng VL tiến vào Quyết Minh Cốc. (@c0086)","tabs":{"diem":[{"text":"Tu vi Trúc Cơ hậu kỳ, sở hữu giả đan","chuong":"@c0086"},{"text":"Đệ tử cao cấp Thi Âm tông, phục lệnh La Sát","chuong":"@c0086"},{"text":"Được phái dẫn nhóm 20 vật dẫn và VL tiến vào Quyết Minh Cốc","chuong":"@c0086"}],"kinhLich":[{"chuong":"@c0086","importance":"major","text":"Được phái dẫn nhóm 20 vật dẫn và VL tiến vào Quyết Minh Cốc. Tu vi Trúc Cơ hậu kỳ có giả đan — đủ để vào trong mà không bị trận phong ấn chặn? (Trận phong ấn Kết Đan+ — Đổ Trần có giả đan nhưng chưa Kết Đan thật, nên vẫn vào được.) (@c0086)"}],"tuVi":"Trúc Cơ hậu kỳ, có giả đan (@c0086).","tuViMoc":[{"chuong":"@c0086","canhGioi":"Trúc Cơ hậu kỳ (giả đan)","text":"Được nhắc rõ tu vi khi La Sát phái dẫn nhóm vật dẫn @c0086."}],"nhanMach":[{"ten":"La Sát / Dạ Tự Tại","quanHe":"Thượng cấp","ghiChu":"Nhận lệnh từ La Sát dẫn nhóm vật dẫn vào Quyết Minh Cốc @c0086.","tag":"su-mon"},{"ten":"Vương Lâm","quanHe":"Thành viên đoàn / đối tượng áp giải","ghiChu":"VL đi cùng nhưng không bị coi là tù nhân @c0086.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0086"]},{"id":"cao-khai-minh","name":"Cao Khải Minh","cn":"","aliases":["thầy toán","#khai-minh"],"gioiTinh":"nam","theLuc":["đồng minh Đằng Hóa Nguyên"],"canhGioiCaoNhat":"Chưa rõ (sở hữu gương cổ, thiên toán chi đạo @c0087)","trangThai":"song","vaiTro":"Chưởng môn Phiêu Miểu Tông — thầy toán, đồng minh Đằng Hóa Nguyên","tinhCach":"Tinh thông thiên toán chi đạo; hành động nhanh gọn, cứu người xong liền rời đi; quyết đoán tự sát để bảo toàn môn phái","blurb":"Cao Khải Minh là chưởng môn Phiêu Miểu Tông, người dùng thuật bói toán và sở hữu gương cổ cùng Thiên toán chi đạo. Là đồng minh của Đằng Hóa Nguyên, ông được phái đến cứu Tứ thúc của Vương Lâm. Sau khi Đằng Hóa Nguyên khai tên trước lúc chết và biết mình bị điểm danh giữa lúc Vương Lâm diệt sạch các thế lực liên quan, ông tự sát ngay tại chỗ để bảo toàn môn phái.","tabs":{"diem":[{"text":"Dùng Thiên toán chi đạo và gương cổ cứu Tứ thúc Vương Lâm theo lệnh Đằng Hóa Nguyên","chuong":"@c0087"},{"text":"Được xác định là chưởng môn Phiêu Miểu Tông, người dùng thuật bói toán","chuong":"@c0222"},{"text":"Tự sát ngay tại chỗ để bảo toàn môn phái khi bị điểm danh","chuong":"@c0223"}],"kinhLich":[{"chuong":"@c0087","importance":"major","text":"Xuất hiện theo lệnh Đằng Hóa Nguyên, dùng Thiên toán chi đạo + gương cổ cứu Tứ thúc Vương Lâm (đang bị giữ làm con tin). (@c0087)"}],"tuVi":"Chưa xác nhận (@c0087).","tuViMoc":[],"nhanMach":[{"ten":"Đằng Hóa Nguyên","quanHe":"Người sai phái","ghiChu":"Phục vụ Đằng Hóa Nguyên như đồng minh/thủ hạ @c0087.","tag":"dong-minh"},{"ten":"Tứ thúc Vương Lâm","quanHe":"Người được cứu","ghiChu":"Cứu Tứ thúc thoát con tin @c0087.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0087"]},{"id":"chu-quyen","name":"Chu Quyền","cn":"","aliases":["bạch y thanh niên","đệ tử Viên phái"],"gioiTinh":"nam","theLuc":["Viên phái"],"canhGioiCaoNhat":"Trúc Cơ kỳ (suy ra — có thể vào Quyết Minh Cốc @c0088)","trangThai":"song","vaiTro":"Đệ tử Viên phái (chính đạo), tu luyện trong Quyết Minh Cốc","tinhCach":"Bình thản, độc lập; tu luyện một mình trong Quyết Minh Cốc.","blurb":"Thanh niên áo trắng thuộc chính đạo, đệ tử Viên phái, tu luyện trong Quyết Minh Cốc. Gặp Vương Lâm trong cốc @c0088. (@c0088)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0088","importance":"normal","text":"Gặp Vương Lâm trong Quyết Minh Cốc; thanh niên áo trắng, là đệ tử Viên phái (chính đạo). Đang tu luyện độc lập trong cốc. (@c0088)"}],"tuVi":"Trúc Cơ kỳ (suy ra từ điều kiện vào Quyết Minh Cốc @c0088).","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Gặp gỡ trong cốc","ghiChu":"Gặp VL trong Quyết Minh Cốc @c0088.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0088"]},{"id":"lam-dich","name":"Lâm Dịch","cn":"","aliases":["Sứ giả Thông Thiên tháp"],"gioiTinh":"nam","theLuc":["Thông Thiên tháp"],"canhGioiCaoNhat":"Cao hơn Nguyên Anh kỳ (toàn bộ Nguyên Anh kỳ hiện diện đều cúi đầu chào @c0097)","trangThai":"song","vaiTro":"Phụ — sứ giả Thông Thiên tháp phụ trách Triệu quốc","tinhCach":"Tươi cười thường trực; uy quyền ngầm khiến toàn bộ Nguyên Anh kỳ kính cẩn; tinh tế nhận ra xuất xứ pháp bảo ngũ cấp tu chân quốc","blurb":"Đại diện Thông Thiên tháp tại Triệu quốc, thân béo tròn như quả bóng, xuất hiện cùng đoàn tùy tùng tại cốc khẩu Quyết Minh Cốc khiến toàn bộ Nguyên Anh kỳ hiện diện cúi đầu chào. Có nhãn lực tinh tế, nhận ra Thiên Huyễn Biến là pháp bảo ngũ cấp tu chân quốc xuất xứ Huyễn thành. Biến sắc và định truy đuổi khi mục tiêu tự nổ thân thể phóng vào thông đạo Vực Ngoại, nhưng bị ngăn lại.","tabs":{"diem":[{"text":"Xuất hiện tại cốc khẩu Quyết Minh Cốc, khiến toàn bộ Nguyên Anh kỳ hiện diện cúi đầu chào — cảnh giới cao hơn Nguyên Anh kỳ","chuong":"@c0097"},{"text":"Nhận ra Thiên Huyễn Biến là pháp bảo ngũ cấp tu chân quốc, xác định xuất xứ từ Huyễn thành","chuong":"@c0098"},{"text":"Biến sắc và định cùng người khổng lồ truy đuổi mục tiêu tự nổ thân phóng vào thông đạo Vực Ngoại, nhưng bị ngăn lại","chuong":"@c0100"}],"kinhLich":[{"chuong":"@c0097","importance":"major","text":"Xuất hiện tại cốc khẩu Quyết Minh Cốc cùng đoàn tùy tùng. Toàn bộ Nguyên Anh kỳ hiện diện cúi đầu chào — thực lực vượt Nguyên Anh. Đi cùng Phác Nam Tử, Hư Mi chân nhân (tóc bạc, đệ nhất Phiêu Miễu tông), lão nhân Thiên Đạo môn. (@c0097)"},{"chuong":"@c0098","importance":"normal","text":"Nhận ra Thiên Huyễn Biến VL dùng là pháp bảo từ ngũ cấp tu chân quốc, xuất xứ Huyễn thành. Xác nhận khi VL phô diễn tu vi giả leo thang trước đám đông. (@c0098)"},{"chuong":"@c0100","importance":"normal","text":"Biến sắc khi VL tự nổ thân thể và phóng vào thông đạo Vực Ngoại; cùng người khổng lồ định truy đuổi nhưng bị lực đẩy ngăn lại. Nói câu cuối 'Là—' bị ngắt — ngụ ý nhận ra VL là ai. (@c0100)"}],"tuVi":"Vượt Nguyên Anh kỳ (toàn bộ Nguyên Anh kỳ cúi đầu @c0097). Cụ thể chưa xác nhận.","tuViMoc":[],"nhanMach":[{"ten":"Phác Nam Tử","quanHe":"Đồng hành","ghiChu":"Cùng đi đến cốc khẩu @c0097.","tag":"dong-hanh"},{"ten":"Hư Mi chân nhân","quanHe":"Đồng hành","ghiChu":"Đi cùng @c0097.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0097","@c0098","@c0100"]},{"id":"hu-mi-chan-nhan","name":"Hư Mi chân nhân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Phiêu Miễu tông"],"canhGioiCaoNhat":"Nguyên Anh kỳ (đệ nhất Phiêu Miễu tông @c0097)","trangThai":"song","vaiTro":"Phụ — đệ nhất cao thủ Phiêu Miễu tông","tinhCach":"Chưa mô tả chi tiết.","blurb":"Đệ nhất cao thủ Phiêu Miễu tông, tóc bạc. Theo Lâm Dịch đến cốc khẩu Quyết Minh Cốc; nhận diện Thi Âm tông nhân khôi (mắt đỏ, âm hàn). (@c0097)","tabs":{"diem":[{"text":"Nhận diện 5 người Thi Âm tông nhân khôi trong đám đông — tóc bạc, kinh nghiệm sâu.","chuong":"@c0097"}],"kinhLich":[{"chuong":"@c0097","importance":"normal","text":"Theo Lâm Dịch đến cốc khẩu Quyết Minh Cốc. Nhận diện và chỉ ra 5 người Thi Âm tông nhân khôi (mắt đỏ hồng, âm hàn bao thân) trong đám đông tu sĩ. (@c0097)"}],"tuVi":"Nguyên Anh kỳ, đệ nhất cao thủ Phiêu Miễu tông (@c0097).","tuViMoc":[{"chuong":"@c0097","canhGioi":"Nguyên Anh kỳ","text":"Xác nhận là đệ nhất Phiêu Miễu tông @c0097."}],"nhanMach":[{"ten":"Tân Hải","quanHe":"Đồng tông (lão tổ khác)","ghiChu":"Cùng tông Phiêu Miễu; Tân Hải là lão tổ, Hư Mi là đệ nhất cao thủ @c0096–97.","tag":"dong-tong"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0097"]},{"id":"tan-hai","name":"Tân Hải","cn":"","aliases":["lão tổ Phiêu Miễu tông"],"gioiTinh":"nam","theLuc":["Phiêu Miễu tông"],"canhGioiCaoNhat":"Nguyên Anh kỳ (lão tổ @c0096)","trangThai":"song","vaiTro":"Phụ — lão tổ Phiêu Miễu tông","tinhCach":"Đau lòng mất đệ tử; thề báo thù kẻ giết người.","blurb":"Lão tổ Nguyên Anh kỳ Phiêu Miễu tông. Dẫn 25 đệ tử vào Quyết Minh Cốc, chỉ còn 8 người ra; thề truy tìm và báo thù kẻ giết 17 đệ tử. (@c0096–@c0097)","tabs":{"diem":[{"text":"Mất 17 trên 25 đệ tử mang vào Quyết Minh Cốc — tổn thất nặng nhất trong các đại tông phái.","chuong":"@c0096"}],"kinhLich":[{"chuong":"@c0096","importance":"normal","text":"Ra khỏi Quyết Minh Cốc với chỉ 8 đệ tử còn sống (vào với 25 người). Đau lòng thề báo thù kẻ giết 17 đệ tử còn lại — chưa biết thủ phạm là VL. (@c0096)"},{"chuong":"@c0097","importance":"minor","text":"Hỏi về Hư Mi chân nhân trong đoàn Lâm Dịch; diện mạo vẫn đầy thù hận sau mất mát trong cốc. (@c0097)"}],"tuVi":"Nguyên Anh kỳ (@c0096).","tuViMoc":[{"chuong":"@c0096","canhGioi":"Nguyên Anh kỳ","text":"Xác nhận là lão tổ Phiêu Miễu tông @c0096."}],"nhanMach":[{"ten":"Hư Mi chân nhân","quanHe":"Đồng tông (đệ nhất cao thủ)","ghiChu":"Cùng Phiêu Miễu tông @c0096–97.","tag":"dong-tong"},{"ten":"Vương Lâm","quanHe":"Kẻ thù (chưa biết)","ghiChu":"Thề báo thù kẻ giết 17 đệ tử — thực ra là VL @c0096.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0096","@c0097"]},{"id":"lao-ma","name":"Lão Mã","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Huyền Đạo Tông"],"canhGioiCaoNhat":"Trúc Cơ trung kỳ (@c0093)","trangThai":"tu-vong","vaiTro":"Phụ — đệ tử Huyền Đạo Tông","tinhCach":"Hung hăng, ra tay trước khi suy nghĩ.","blurb":"Tu sĩ Trúc Cơ trung kỳ Huyền Đạo Tông. Ra tay khi VL xuất hiện tại điểm tập kết — bị VL giết bằng một chiêu băng hóa. Chết @c0093.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0093","importance":"normal","text":"Tại điểm tập kết Huyền Đạo Tông, thấy VL xuất hiện liền ra tay tấn công. Bị Vương Lâm dùng Cực cảnh linh lực băng hóa tức thời — chết bằng một chiêu. Liễu Phong và đám đệ tử Huyền Đạo Tông kinh ngạc chứng kiến. (@c0093)"}],"tuVi":"Trúc Cơ trung kỳ (@c0093). Chết @c0093.","tuViMoc":[{"chuong":"@c0093","canhGioi":"Trúc Cơ trung kỳ","text":"Tu vi xác nhận khi xuất hiện tại điểm tập kết; bị giết ngay lập tức."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Kẻ hạ sát","ghiChu":"Tấn công VL và bị giết bằng một chiêu @c0093.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0093"]},{"id":"thuong-quan-van","name":"Thượng Quan Vân","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Chưa xác định rõ"],"canhGioiCaoNhat":"Nguyên Anh kỳ (lão tổ hiện diện tại cốc khẩu @c0096)","trangThai":"song","vaiTro":"Phụ — lão tổ Nguyên Anh kỳ tại cốc khẩu","tinhCach":"Chưa mô tả chi tiết.","blurb":"Lão tổ Nguyên Anh kỳ, xuất hiện tại cốc khẩu Quyết Minh Cốc @c0096–97, đứng cạnh lão tổ Tân Hải. Là thực thể RIÊNG — khác hẳn 'Thượng Quan trưởng lão' (Trúc Cơ kỳ, Hằng Nhạc Phái @c0051).","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0096","importance":"minor","text":"Xuất hiện tại cốc khẩu Quyết Minh Cốc sau khi thông đạo mở. (@c0096)"}],"tuVi":"Nguyên Anh kỳ, xác nhận là lão tổ @c0096.","tuViMoc":[{"chuong":"@c0096","canhGioi":"Nguyên Anh kỳ","text":"Hiện diện như lão tổ tại cốc khẩu @c0096."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0096","@c0097"]},{"id":"nguoi-khong-lo","name":"Người Khổng Lồ (thực thể Vực Ngoại)","cn":"","aliases":["người khổng lồ sọ đầu lâu"],"gioiTinh":"khong-ro","theLuc":["Thông Thiên tháp (liên hệ)"],"canhGioiCaoNhat":"Không xác định — vượt Nguyên Anh kỳ (ép lùi Lâm Dịch @c0100)","trangThai":"hiện-dien","vaiTro":"Phụ bí ẩn — thực thể canh giữ/kích hoạt thông đạo Vực Ngoại","tinhCach":"Bí ẩn — không lời thoại được ghi nhận.","blurb":"Thực thể khổng lồ hình sọ người xuất hiện khi Đằng Hóa Nguyên kích hoạt thông đạo Vực Ngoại. Mở ra không gian thông đạo. Biến sắc khi VL tự nổ thân xuyên vào — cùng Lâm Dịch định truy đuổi nhưng bị lực đẩy ngăn lại. (@c0099–@c0100)","tabs":{"diem":[{"text":"Thực lực ép Lâm Dịch không thể theo vào thông đạo — vượt hoặc ngang Lâm Dịch về quyền hạn với thông đạo Vực Ngoại.","chuong":"@c0100"}],"kinhLich":[{"chuong":"@c0099","importance":"normal","text":"Xuất hiện khi Đằng Hóa Nguyên dùng Hồn Phiên kích hoạt Vực Ngoại thông đạo. Hình người khổng lồ sọ đầu lâu; mở ra cổng thông đạo. (@c0099)"},{"chuong":"@c0100","importance":"normal","text":"Biến sắc khi VL tự nổ thân xuyên vào thông đạo. Định truy đuổi cùng Lâm Dịch nhưng bị lực đẩy ngăn lại. (@c0100)"}],"tuVi":"Không xác định. Thực lực đủ để ngăn Lâm Dịch (vượt Nguyên Anh kỳ) @c0100.","tuViMoc":[],"nhanMach":[{"ten":"Lâm Dịch","quanHe":"Cùng hiện diện / bị ngăn chặn","ghiChu":"Cùng biến sắc và định truy đuổi VL @c0100.","tag":"lien-he"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0099","@c0100"]},{"id":"ma-luong","name":"Mã Lương","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc","Chiến Thần Điện — ký danh đệ tử Phượng Loan lão tổ @c0119"],"canhGioiCaoNhat":"Trúc Cơ kỳ (cụ thể không rõ; có thể đoán từ môi trường chiến trường ngoại vực max Trúc Cơ hậu kỳ)","trangThai":"tu-vong (bị Cát Dương giết @c0103; thân xác bị Vương Lâm đoạt xá)","vaiTro":"Nhân vật phụ — đệ tử Chiến Thần Điện, thân xác Vương Lâm đoạt xá","tinhCach":"Nhiều kinh nghiệm chiến trường hơn 30 năm; tham lợi, sẵn sàng dâng túi trữ vật cầu sống; kiên trì đuổi bảo vật","blurb":"Mã Lương là đệ tử Chiến Thần Điện từ Hỏa Phần Quốc, gương mặt trắng bệch với hơn 30 năm kinh nghiệm ở chiến trường ngoại vực. Khi đang đào bộ giáp từ xác người khổng lồ Cự Ma tộc, hắn bỏ giáp đuổi theo hạt châu bay qua nhưng bị Hứa Hạo và Cát Dương phục kích; dâng cả túi trữ vật cầu sống vẫn bị Cát Dương giết. Thân xác của hắn trở thành vật chủ để Vương Lâm đoạt xá.","tabs":{"diem":[{"text":"Đệ tử Chiến Thần Điện từ Hỏa Phần Quốc, hơn 30 năm kinh nghiệm ở chiến trường ngoại vực","chuong":"@c0101"},{"text":"Bỏ bộ giáp đang đào để đuổi theo hạt châu Cự Ma tộc","chuong":"@c0101"},{"text":"Bị Hứa Hạo và Cát Dương phục kích, dâng túi trữ vật cầu sống nhưng vẫn bị Cát Dương giết","chuong":"@c0103"},{"text":"Thân xác trở thành vật chủ Vương Lâm đoạt xá","chuong":"@c0103"}],"kinhLich":[{"chuong":"@c0101","importance":"normal","text":"Đang đào bộ giáp từ xác người khổng lồ Cự Ma tộc thì một đạo ánh sáng chứa hạt châu lao qua; bỏ giáp, cầm con thoi đỏ đuổi theo ba ngày không kịp. Vùng xa lạ xuất hiện vô số vệt trắng — dấu hiệu vết rách không gian — hạt châu chui vào vết rách biến mất. Bị cường giả Cự Ma tộc Anh Biến kỳ vỗ vai lạnh toát, hút lấy con thoi đỏ rồi bỏ đi. (@c0101)"},{"chuong":"@c0103","importance":"major","text":"Đang đuổi phi kiếm tử quang tự bay thì bị Hứa Hạo và Cát Dương phục kích. Dâng cả túi trữ vật cầu sống; Hứa Hạo tha nhưng Cát Dương phóng phi kiếm xuyên ngực giết chết. Thi thể trở thành vật chủ — một luồng thần thức khổng lồ của VL nhập vào, chữa lành vết thương, mở mắt. Mã Lương chính thức chết. (@c0103)"},{"chuong":"@c0111","importance":"normal","text":"(VL trong thân Mã Lương) Rời hang bế quan, đến Phần Kim sơn mạch. Phát hiện và tiêu diệt ba tay sai Thi Âm Tông theo dõi khu vực. (@c0111)"},{"chuong":"@c0113","importance":"normal","text":"(VL trong thân Mã Lương) Dùng tên Mã Lương gặp Lý Kỳ Khánh (Lạc Hà Môn) và Tôn Hữu Tài (Tà Ma Tông). Trên đường đến Chiến Thần Điện. (@c0113)"},{"chuong":"@c0119","importance":"major","text":"(VL trong thân Mã Lương) Được Phượng Loan lão tổ Nguyên Anh sơ kỳ (Chiến Thần Điện) chính thức thu làm ký danh đệ tử — mối quan hệ bảo hộ quan trọng tại Hỏa Phần quốc. Dương Sâm (Nguyên Anh trung kỳ, đạo lữ Phượng Loan) tặng ngọc phù bảo mệnh. (@c0119)"}],"tuVi":"Trúc Cơ kỳ (cụ thể không rõ). Mặt trắng bệch đặc trưng tu sĩ chiến trường ngoại vực. Linh lực cạn kiệt hoàn toàn tại thời điểm VL đoạt xá @c0104.","tuViMoc":[],"nhanMach":[{"ten":"Tiểu sư muội (Từ Tư)","quanHe":"Hôn thê (cũ)","ghiChu":"Mã Lương si mê tiểu sư muội, lo nàng bị đại sư huynh chiếm; Từ Tư thực ra muốn Mã Lương chết @c0109.","tag":"than-thiet"},{"ten":"Hoắc Hồng Phi","quanHe":"Trưởng lão / cấp trên","ghiChu":"Trưởng lão Kết Đan sơ kỳ Chiến Thần Điện, đón đoàn về @c0109.","tag":"su-mon"},{"ten":"Phượng Loan","quanHe":"Sư tổ (ký danh)","ghiChu":"Nguyên Anh sơ kỳ, Chiến Thần Điện — thu VL (trong thân Mã Lương) làm ký danh đệ tử @c0119.","tag":"su-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0101","@c0103","@c0104","@c0111","@c0113","@c0119"]},{"id":"cuong-gia-cu-ma-toc","name":"Cường giả Cự Ma Tộc (Anh Biến kỳ)","cn":"","aliases":["trung niên hán tử","hán tử đồ án cây búa"],"gioiTinh":"nam","theLuc":["Cự Ma Tộc"],"canhGioiCaoNhat":"Anh Biến kỳ (tùy ý thay đổi kích thước thân thể — đặc trưng Cự Ma tộc Anh Biến kỳ @c0101)","trangThai":"hiện-dien","vaiTro":"Phụ đối nghịch — thế lực ngũ cấp xâm nhập chiến trường","tinhCach":"Ngang ngược, nổi tiếng chuyên chiếm đoạt đồ vật kẻ khác; không dùng lực nếu đe dọa miệng đã đủ.","blurb":"Cường giả Cự Ma tộc Anh Biến kỳ — mi tâm khắc đồ án cây búa, dáng người thường (dấu hiệu đạt Anh Biến kỳ). Theo hạt châu từ Triệu quốc sang chiến trường ngoại vực nhưng thất bại. Tước đoạt con thoi đỏ Mã Lương. Nổi tiếng chuyên chiếm đoạt đồ vật ở ngũ cấp tu chân quốc. (@c0101)","tabs":{"diem":[{"text":"Đạt Anh Biến kỳ — tùy ý thay đổi kích thước thân thể (đặc trưng bẩm sinh của Cự Ma tộc ở cảnh giới này).","chuong":"@c0101"}],"kinhLich":[{"chuong":"@c0101","importance":"normal","text":"Đuổi hạt châu từ Triệu quốc sang chiến trường ngoại vực nhưng hạt châu chui vào vết rách không gian biến mất. Gặp Mã Lương, hút lấy con thoi đỏ tuyên bố 'vật này từ nay thuộc về lão tử'. Bỏ đi trong căm tức. Nổi danh ở ngũ cấp tu chân quốc với tính chuyên chiếm đoạt; Mã Lương (tam cấp) không biết danh. (@c0101)"}],"tuVi":"Anh Biến kỳ — đặc trưng Cự Ma tộc: trời sinh linh lực, tùy ý thay đổi kích thước thân thể khi đạt Anh Biến kỳ @c0101.","tuViMoc":[{"chuong":"@c0101","canhGioi":"Anh Biến kỳ","text":"Xác nhận qua khả năng tùy ý thu nhỏ về kích thước người thường @c0101."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0101"]},{"id":"chu-tu-hong","name":"Chu Tử Hồng","cn":"","aliases":["sư muội"],"gioiTinh":"nu","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ (sau đợt Vực Ngoại @c0109)","trangThai":"song (nô tài của Vương Lâm — bản mệnh tinh huyết @c0106)","vaiTro":"Nhân vật phụ — đệ tử Chiến Thần Điện, từng là nô tài của Vương Lâm","tinhCach":"Bình tĩnh, gan dạ; trực tiếp, dám hỏi thẳng; biết giữ bí mật; cầu tiến trong tu luyện","blurb":"Chu Tử Hồng là đệ tử Chiến Thần Điện, từng tiến vào chiến trường Vực Ngoại và được Vương Lâm trong thân phận Mã Lương cứu khỏi du hồn. Nàng nhận ra việc Vương Lâm đoạt xá nhưng vẫn bình tĩnh hỏi thẳng, sau đó quy phục và dâng bản mệnh tinh huyết; về sau được Vương Lâm thả lại bản mệnh tinh huyết. Tới mốc sau này, nàng được ghi nhận ở Chiến Thần Điện với tu vi Hóa Thần Hậu Kỳ, chuẩn bị xung kích Anh Biến.","tabs":{"diem":[{"text":"Được Vương Lâm cứu khỏi du hồn trong chiến trường Vực Ngoại.","chuong":"@c0105"},{"text":"Nhận ra Vương Lâm đoạt xá Mã Lương nhưng vẫn bình tĩnh hỏi thẳng sự thật.","chuong":"@c0106"},{"text":"Trở về Hỏa Phần Quốc sau đợt Vực Ngoại và đạt Trúc Cơ hậu kỳ.","chuong":"@c0109"},{"text":"Được Vương Lâm thả, trả lại bản mệnh tinh huyết.","chuong":"@c0113"},{"text":"Thừa nhận Phượng Loan lão tổ chính là mẫu thân của nàng.","chuong":"@c0123"},{"text":"Được ghi nhận ở Hóa Thần Hậu Kỳ tại Chiến Thần Điện, chuẩn bị xung kích Anh Biến.","chuong":"@c0846"}],"kinhLich":[{"chuong":"@c0104","importance":"normal","text":"Cùng hai đồng môn đang bị du hồn truy đuổi trong chiến trường khi VL (thân Mã Lương) xuất hiện. (@c0104)"},{"chuong":"@c0105","importance":"normal","text":"Được VL cứu bằng một tiếng quát thần thức khiến du hồn giải tán. (@c0105)"},{"chuong":"@c0106","importance":"major","text":"Nhận ra VL đoạt xá; bình tĩnh hỏi thẳng 'Mã Lương sống hay chết?'. VL đáp 'Chết'. Nàng thở phào, tin lời thật, rồi dâng bản mệnh tinh huyết quy phục. Ba điểm sáng (kể cả của nàng) neo trong thần thức VL. (@c0106)"},{"chuong":"@c0109","importance":"normal","text":"Được truyền tống về Hỏa Phần Quốc trước VL. Ra mắt Hoắc Hồng Phi. Đạt Trúc Cơ hậu kỳ sau đợt Vực Ngoại. Che giấu chuyện đã giao bản mệnh tinh huyết cho VL. (@c0109)"},{"chuong":"@c0113","importance":"normal","text":"VL (thân Mã Lương) thả nàng, trả lại bản mệnh tinh huyết của nàng về cho sư tổ bào y lam Nguyên Anh — VL không còn kiểm soát sinh tử Chu Tử Hồng từ đây. (@c0113)"},{"chuong":"@c0119","importance":"normal","text":"Ở tuyến khác: sư tổ Phượng Loan (bào y lam Nguyên Anh sơ kỳ) gặp VL và thu VL làm ký danh đệ tử — Chu Tử Hồng có thêm liên hệ với VL qua tuyến sư môn này. (@c0119)"},{"chuong":"@c0123","importance":"normal","text":"Được Dương Hùng gọi tới gặp VL; thừa nhận Phượng Loan lão tổ chính là mẫu thân của nàng. Đổi việc lấy tấm bản đồ giúp VL lấy điều kiện hắn giết Từ Tư và Chu An; ném ngọc giản bản đồ cho VL rồi rời đi, thầm nói đây là việc cuối cùng nàng giúp 'Mã Lương'. (@c0123)"}],"tuVi":"Kết Đan kỳ (mục tiêu, thề không kết đôi trước đó @c0106). Đạt Trúc Cơ hậu kỳ sau đợt Vực Ngoại @c0109.","tuViMoc":[{"chuong":"@c0109","canhGioi":"Trúc Cơ hậu kỳ","text":"Xác nhận sau khi trở về từ Vực Ngoại @c0109."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Chủ nhân (bản mệnh tinh huyết)","ghiChu":"VL nắm giữ bản mệnh tinh huyết; trả lại cho sư tổ Phượng Loan @c0113 — VL không còn kiểm soát Chu Tử Hồng.","tag":"thu-phuc"},{"ten":"Hoắc Hồng Phi","quanHe":"Sư phụ","ghiChu":"Trưởng lão Kết Đan sơ kỳ Chiến Thần Điện @c0109.","tag":"su-mon"},{"ten":"Phượng Loan","quanHe":"Mẫu thân","ghiChu":"Nguyên Anh sơ kỳ, Chiến Thần Điện; Chu Tử Hồng thừa nhận Phượng Loan là mẫu thân của nàng @c0123. Nhận lại bản mệnh tinh huyết từ VL @c0113; thu VL làm ký danh đệ tử @c0119.","tag":"cha-me"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0104","@c0105","@c0106","@c0109","@c0113","@c0119","@c0123"]},{"id":"lam-dao","name":"Lâm Đào","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Dưới Trúc Cơ hậu kỳ một bậc, chuẩn bị đột phá @c0109","trangThai":"song (nô tài của Vương Lâm — bản mệnh tinh huyết @c0106)","vaiTro":"Nhân vật phụ — nô tài của Vương Lâm","tinhCach":"Đa nghi, nhanh trí; thực dụng, dứt khoát trong quyết định giữ mạng; có mưu đồ riêng, sẵn sàng làm gián điệp","blurb":"Một trong ba nô tài của Vương Lâm, thông minh và dứt khoát nhất trong nhóm. Nhận ra Vương Lâm đã đoạt xá, hắn lập tức quỳ xin quy phục và tự tay dâng bản mệnh tinh huyết để giữ mạng. Về sau bị Phượng Loan lão tổ bắt quả tang sao chép địa đồ bí mật, lộ thân phận gián điệp và bị giữ lại xử lý (@c0105–@c0119).","tabs":{"diem":[{"text":"Nhận ra du hồn được lệnh giết mình để thử lòng nhưng không bỏ chạy","chuong":"@c0105"},{"text":"Đoán ra việc đoạt xá, quỳ xin làm nô tài và dâng bản mệnh tinh huyết đầu tiên","chuong":"@c0106"},{"text":"Tu vi dưới Trúc Cơ hậu kỳ một bậc, chuẩn bị đột phá; được truyền tống về Hỏa Phần Quốc trước Vương Lâm","chuong":"@c0109"},{"text":"Nằm trong nhóm nô bộc được thả, được hẹn gặp lại trong 10 ngày","chuong":"@c0112"},{"text":"Bị Phượng Loan lão tổ bắt quả tang sao chép địa đồ bí mật, lộ hành vi gián điệp","chuong":"@c0119"}],"kinhLich":[{"chuong":"@c0105","importance":"normal","text":"VL ra lệnh cho du hồn giết Lâm Đào — thử lòng. Lâm Đào nhận ra thực trạng và không bỏ chạy. (@c0105)"},{"chuong":"@c0106","importance":"major","text":"Đoán ra đoạt xá, không dám hé răng. Tự xưng không có giao tình với Mã Lương. Quỳ xin làm nô tài, dâng bản mệnh tinh huyết đầu tiên. Sau khi quy hàng còn chủ động chĩa phi kiếm vào Dương Hùng để tỏ thái độ. (@c0106)"},{"chuong":"@c0109","importance":"minor","text":"Được truyền tống về Hỏa Phần Quốc trước VL. Tu vi dưới Trúc Cơ hậu kỳ một bậc, chuẩn bị đột phá. Tiết lộ 'Mã Lương còn ở phía sau, nhường ba người về trước' với Hoắc Hồng Phi. (@c0109)"},{"chuong":"@c0112","importance":"minor","text":"VL hẹn gặp cả ba nô bộc trong 10 ngày; Lâm Đào trong nhóm được thả. (@c0112)"},{"chuong":"@c0119","importance":"major","text":"Bị Phượng Loan lão tổ bắt quả tang sao chép địa đồ bí mật — lộ hành vi gián điệp. Bị Phượng Loan giữ lại xử lý. (@c0119)"}],"tuVi":"Gần Trúc Cơ hậu kỳ — một bậc dưới, chuẩn bị đột phá @c0109.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Chủ nhân (bản mệnh tinh huyết)","ghiChu":"VL nắm giữ bản mệnh tinh huyết @c0106.","tag":"thu-phuc"},{"ten":"Phượng Loan","quanHe":"Người bắt giữ","ghiChu":"Phượng Loan bắt Lâm Đào khi sao chép địa đồ @c0119.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0105","@c0106","@c0109","@c0112","@c0119"]},{"id":"duong-hung","name":"Dương Hùng","cn":"","aliases":["sư huynh họ Dương"],"gioiTinh":"nam","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ (sau đợt Vực Ngoại @c0109)","trangThai":"song (nô tài của Vương Lâm — bản mệnh tinh huyết @c0106)","vaiTro":"Nhân vật phụ — nô tài của Vương Lâm, đệ tử Chiến Thần Điện","tinhCach":"Nhạy bén, sớm đoán ra chuyện đoạt xá; sợ hãi nên dâng bản mệnh tinh huyết quy phục; hai lòng, từng định báo cáo sự thật; khéo che giấu, biết bịa chuyện để giữ bí mật","blurb":"Dương Hùng là sư huynh họ Dương trong nhóm, có liên hệ với Chiến Thần Điện và từng bị Vương Lâm khống chế bằng bản mệnh tinh huyết. Sau khi đoán ra Vương Lâm đoạt xá, y quy phục vì sợ bị đoạt thân, nhưng vẫn âm thầm định báo cáo sự thật cho Chiến Thần Điện. Về sau Dương Hùng tiếp tục xuất hiện tại Chiến Thần Điện ở Hỏa Phần Quốc, tu vi được ghi nhận là Hóa Thần Hậu Kỳ.","tabs":{"diem":[{"text":"Sớm đoán ra Vương Lâm đoạt xá, vì sợ bị đoạt thân nên dâng bản mệnh tinh huyết quy phục","chuong":"@c0106"},{"text":"Sau khi trở về từ Vực Ngoại, được xác nhận đạt Trúc Cơ hậu kỳ","chuong":"@c0109"},{"text":"Bịa chuyện đan dược trú nhan để che giấu khi bị Từ Tư đòi giải thích","chuong":"@c0109"},{"text":"Bị Vương Lâm phát hiện đang chuẩn bị dùng ngọc phù báo cáo sự thật đoạt xá cho Chiến Thần Điện","chuong":"@c0112"},{"text":"Dẫn Vương Lâm vào gặp Phượng Loan lão tổ và xác nhận danh tính với Phượng Loan","chuong":"@c0119"},{"text":"Tại Chiến Thần Điện ở Hỏa Phần Quốc, tu vi được ghi nhận là Hóa Thần Hậu Kỳ","chuong":"@c0846"}],"kinhLich":[{"chuong":"@c0106","importance":"major","text":"Đoán ra đoạt xá, sợ VL đoạt thân mình. Cười khổ, dâng bản mệnh tinh huyết quy phục. An ủi Chu Tử Hồng. (@c0106)"},{"chuong":"@c0109","importance":"normal","text":"Được truyền tống về trước VL. Đạt Trúc Cơ hậu kỳ. Bịa chuyện đan dược trú nhan khi Từ Tư đòi hỏi giải thích vì sao không già sau 50 năm. (@c0109)"},{"chuong":"@c0112","importance":"major","text":"VL phát hiện Dương Hùng đang ôm ngọc phù chuẩn bị báo cáo cho Chiến Thần Điện về sự thật VL đoạt xá. VL lập tức thu hồi bản mệnh tinh huyết của Dương Hùng — trừng phạt phản bội. (@c0112)"},{"chuong":"@c0119","importance":"normal","text":"Dẫn VL vào gặp Phượng Loan lão tổ, xác nhận danh tính VL với Phượng Loan. (@c0119)"},{"chuong":"@c0123","importance":"normal","text":"Bị VL khống chế, dùng ngọc giản gọi Chu Tử Hồng tới gặp VL; đổi lại VL phóng thích bản mệnh tinh huyết cho Dương Hùng — hắn nhận lấy, xấu hổ không dám nhìn Chu Tử Hồng rồi rời đi. (@c0123)"}],"tuVi":"Trúc Cơ hậu kỳ @c0109.","tuViMoc":[{"chuong":"@c0109","canhGioi":"Trúc Cơ hậu kỳ","text":"Xác nhận sau khi trở về từ Vực Ngoại @c0109."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Cố nhân (đã được giải khống chế)","ghiChu":"VL từng nắm rồi thu hồi bản mệnh tinh huyết @c0112; sau phóng thích lại cho Dương Hùng để đổi việc gọi Chu Tử Hồng @c0123.","tag":"thu-phuc"},{"ten":"Điện chủ Chiến Thần Điện","quanHe":"Sư phụ / trưởng bối","ghiChu":"Đệ tử đắc ý của Điện chủ @c0109.","tag":"su-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0106","@c0109","@c0112","@c0119","@c0123"]},{"id":"hua-hao","name":"Hứa Hạo","cn":"","aliases":["đại đệ tử thứ sáu Linh Vũ Tông"],"gioiTinh":"nam","theLuc":["Linh Vũ Tông","Cự Lộc Quốc"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ (@c0103)","trangThai":"tu-vong (xác nhận tử vong tại chiến trường ngoại vực @c0105)","vaiTro":"Nhân vật phụ — đối thủ/sát thủ chiến trường của Linh Vũ Tông","tinhCach":"Thực dụng, hành xử vì lợi ích; hợp tác với đồng đảng để đoạt bảo; giữ chữ tín trong thỏa thuận — tha mạng sau khi nhận túi trữ vật","blurb":"Hứa Hạo là đại đệ tử thứ sáu Linh Vũ Tông (Cự Lộc Quốc), tu vi Trúc Cơ hậu kỳ, mang thanh danh xấu là sát thủ 'giết người đoạt bảo' cùng đồng đảng Cát Dương. Hắn nhận tin qua ngọc giản rồi cùng phục kích Mã Lương để cướp phi kiếm tử quang, tha mạng đối phương sau khi nhận túi trữ vật. Về sau hắn tử vong tại chiến trường ngoại vực, túi trữ vật rơi vào tay du hồn hai sừng.","tabs":{"diem":[{"text":"Đạt cảnh giới Trúc Cơ hậu kỳ","chuong":"@c0103"},{"text":"Đại đệ tử thứ sáu Linh Vũ Tông, mang thanh danh sát thủ 'giết người đoạt bảo' cùng đồng đảng Cát Dương","chuong":"@c0103"},{"text":"Nhận tin qua ngọc giản, phục kích Mã Lương để cướp phi kiếm tử quang rồi tha mạng sau khi lấy túi trữ vật","chuong":"@c0103"},{"text":"Xác nhận tử vong tại chiến trường ngoại vực; túi trữ vật bị du hồn hai sừng chiếm giữ","chuong":"@c0105"}],"kinhLich":[{"chuong":"@c0103","importance":"major","text":"Nhận tin từ Cát Dương qua ngọc giản, cùng phục kích Mã Lương để cướp phi kiếm tử quang. Sau khi nhận túi trữ vật, tha mạng Mã Lương theo thỏa thuận 「túi đến tay ai là của đó」 với Cát Dương, nhưng Cát Dương vẫn giết Mã Lương. (@c0103)"},{"chuong":"@c0105","importance":"normal","text":"Ba thôn hồn (theo lệnh VL) đi tìm Hứa Hạo — xác nhận đã tử vong. Túi trữ vật của hắn bị du hồn hai sừng nắm giữ; VL thu lại. (@c0105)"}],"tuVi":"Trúc Cơ hậu kỳ @c0103.","tuViMoc":[{"chuong":"@c0103","canhGioi":"Trúc Cơ hậu kỳ","text":"Xác nhận trong phần giới thiệu @c0103."}],"nhanMach":[{"ten":"Cát Dương","quanHe":"Đồng đảng","ghiChu":"Thường liên thủ giết người đoạt bảo; có thỏa thuận về túi trữ vật.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0103","@c0105","@c0107"]},{"id":"cat-duong","name":"Cát Dương","cn":"","aliases":["Cát Đằng (dị bản — chưa xác nhận)"],"gioiTinh":"nam","theLuc":["Không rõ tông môn"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ (@c0103)","trangThai":"tu-vong (xác nhận tử vong tại chiến trường ngoại vực @c0105)","vaiTro":"Nhân vật phụ — sát thủ/đối thủ tại chiến trường ngoại vực","tinhCach":"Tàn nhẫn, coi trọng lợi ích riêng — giết Mã Lương dù Hứa Hạo đã tha; lạnh lùng, hành sự dứt khoát","blurb":"Cát Dương (còn xuất hiện dưới dạng 'Cát Đằng', dị bản chưa xác nhận) là đồng đảng của Hứa Hạo tại chiến trường ngoại vực, tu vi Trúc Cơ hậu kỳ. Hắn liên thủ phục kích giết người đoạt bảo, và tự tay hạ sát Mã Lương dù Hứa Hạo đã tha vì thỏa thuận chia túi trữ vật không có lợi cho hắn. Cát Dương tử vong tại chiến trường; túi trữ vật của hắn sau đó bị du hồn nắm giữ và bị VL thu lại.","tabs":{"diem":[{"text":"Tu vi Trúc Cơ hậu kỳ, cảnh giới cao nhất ghi nhận","chuong":"@c0103"},{"text":"Phục kích cùng Hứa Hạo, trao tin qua ngọc giản trong trận đoạt bảo","chuong":"@c0103"},{"text":"Phóng phi kiếm giết Mã Lương dù Hứa Hạo đã tha vì hận túi trữ vật không vào tay mình","chuong":"@c0103"},{"text":"Xác nhận tử vong tại chiến trường; ba thôn hồn được VL phái đi tìm","chuong":"@c0105"},{"text":"Túi trữ vật bị du hồn nắm giữ, sau đó VL thu lại","chuong":"@c0105"}],"kinhLich":[{"chuong":"@c0103","importance":"major","text":"Phục kích cùng Hứa Hạo. Trao tin qua ngọc giản. Sau khi Hứa Hạo nhận túi và tha Mã Lương, hắn phóng phi kiếm xuyên ngực Mã Lương: 'Ta chưa nói tha ngươi.' Nguyên nhân: thỏa thuận 'túi đến tay ai của đó' — túi rơi vào tay Hứa Hạo, hắn không được gì. (@c0103)"},{"chuong":"@c0105","importance":"normal","text":"Ba thôn hồn đi tìm Cát Dương theo lệnh VL — xác nhận đã tử vong. Túi trữ vật bị du hồn nắm giữ; VL thu lại. (@c0105)"}],"tuVi":"Trúc Cơ hậu kỳ @c0103.","tuViMoc":[{"chuong":"@c0103","canhGioi":"Trúc Cơ hậu kỳ","text":"Xác nhận trong phần giới thiệu @c0103."}],"nhanMach":[{"ten":"Hứa Hạo","quanHe":"Đồng đảng","ghiChu":"Thường liên thủ; mâu thuẫn về túi trữ vật dẫn đến Cát Dương giết Mã Lương @c0103.","tag":"dong-hanh"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0103","@c0105","@c0107"]},{"id":"hoac-hong-phi","name":"Hoắc Hồng Phi","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Kết Đan sơ kỳ (@c0109)","trangThai":"song (đang hoạt động tại Chiến Thần Điện)","vaiTro":"Nhân vật phụ — trưởng lão Chiến Thần Điện","tinhCach":"Thận trọng — cảm nhận khí tức kỳ lạ từ VL nhưng không dám truy đuổi dù linh lực cao hơn; nghiêm khắc với thuộc hạ (mắng Từ Tư)","blurb":"Trưởng lão Kết Đan sơ kỳ của Chiến Thần Điện, sư phụ Chu Tử Hồng, hơn 200 tuổi nhưng nhờ tu Thần Đạo Thuật trông như trung niên khoảng 40. Đón nhóm Chu Tử Hồng về truyền tống trận trên đỉnh núi lửa sau Vực Ngoại. Khi cảm nhận hàn ý từ linh hồn VL (giả Mã Lương), ông co rút đồng tử, không dám truy đuổi và định báo Điện chủ xử lý.","tabs":{"diem":[{"text":"Trưởng lão Kết Đan sơ kỳ của Chiến Thần Điện, sư phụ Chu Tử Hồng","chuong":"@c0109"},{"text":"Hơn 200 tuổi nhưng nhờ tu Thần Đạo Thuật trông như trung niên khoảng 40","chuong":"@c0109"},{"text":"Đón nhóm Chu Tử Hồng về truyền tống trận trên đỉnh núi lửa","chuong":"@c0109"},{"text":"Cảm nhận hàn ý từ linh hồn VL, co rút đồng tử và không dám truy đuổi","chuong":"@c0109"}],"kinhLich":[{"chuong":"@c0109","importance":"major","text":"Đón nhóm Chu Tử Hồng về truyền tống trận trên đỉnh núi lửa. Mắng Từ Tư. Khi VL (giả Mã Lương) bước ra tỏa hàn ý lạnh giá, Hoắc Hồng Phi co rút đồng tử — kiêng kị, không dám giữ lại hay truy đuổi. Định báo Điện chủ và mời Loan Phương sư tổ xuất quan tra hỏi. (@c0109)"}],"tuVi":"Kết Đan sơ kỳ @c0109.","tuViMoc":[{"chuong":"@c0109","canhGioi":"Kết Đan sơ kỳ","text":"Xác nhận @c0109."}],"nhanMach":[{"ten":"Chu Tử Hồng","quanHe":"Đệ tử","ghiChu":"Từng cấp pháp bảo quý cho Chu Tử Hồng khi vào Vực Ngoại @c0109.","tag":"su-mon"},{"ten":"Từ Tư","quanHe":"Cấp dưới / người quen","ghiChu":"Quát mắng Từ Tư khi nàng thất thanh @c0109.","tag":"dong-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0109"]},{"id":"tu-tu","name":"Từ Tư","cn":"","aliases":["tiểu sư muội (theo Mã Lương)"],"gioiTinh":"nu","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Không rõ (tu Chiến Thần Quyết — công pháp trú nhan @c0103)","trangThai":"song (đang sống tại Hỏa Phần Quốc)","vaiTro":"Nhân vật phụ — hôn thê cũ Mã Lương, tu Chiến Thần Quyết","tinhCach":"Từ bỏ tình cảm cũ, mong Mã Lương đã chết và có tình lang mới; bẽ bàng, thất thanh khi biết hắn còn sống; ra tay tập kích bằng hắc châm","blurb":"Thiếu phụ xinh đẹp, hôn thê cũ đính ước từ thuở ấu thơ của Mã Lương, cùng vào Chiến Thần Điện. Tu Chiến Thần Quyết giữ nhan sắc nên sau 50 năm vẫn trông như ~30 tuổi, nhưng đã có tình lang mới và mong Mã Lương chết đi. Về sau tập kích VL bằng hắc châm, bị xóa ký ấn tinh thần đến ộc máu, rồi bị Chu Tử Hồng liệt vào danh sách VL phải giết.","tabs":{"diem":[{"text":"Tu Chiến Thần Quyết giữ nhan sắc, sau 50 năm vẫn trông như ~30 tuổi","chuong":"@c0103"},{"text":"Xuất hiện tại truyền tống trận cùng tình lang mới, đòi đan dược trú nhan","chuong":"@c0109"},{"text":"Đính hôn với Mã Lương từ thuở ấu thơ, cùng vào Chiến Thần Điện","chuong":"@c0110"},{"text":"Tập kích VL bằng hắc châm, bị xóa ký ấn tinh thần đến ộc máu","chuong":"@c0119"},{"text":"Bị Chu Tử Hồng đưa vào danh sách hai người VL phải giết để đổi bản đồ","chuong":"@c0123"}],"kinhLich":[{"chuong":"@c0103","importance":"minor","text":"Được nhắc gián tiếp qua ký ức Mã Lương: tu Chiến Thần quyết (giữ nhan sắc), sau 50 năm nhìn như ~30 tuổi; Mã Lương si mê, lo đại sư huynh chiếm. (@c0103)"},{"chuong":"@c0109","importance":"normal","text":"Có mặt tại truyền tống trận cùng người đàn ông mới (tình lang hiện tại). Đòi hỏi đan dược trú nhan từ nhóm về; Chu Tử Hồng đẩy sang 'hỏi Mã Lương'. Biết Mã Lương còn sống — biến sắc thất thanh. Bị Hoắc Hồng Phi quát. (@c0109)"},{"chuong":"@c0110","importance":"normal","text":"Nhớ lại quá khứ với Mã Lương: hai người đính hôn từ thuở ấu thơ, cùng vào Chiến Thần Điện, nàng từng hứa sẽ làm lữ tu bạn lữ nếu Mã Lương trở về. Nhưng 50 năm trôi qua — nàng đã thay lòng. (@c0110)"},{"chuong":"@c0119","importance":"major","text":"Tập kích VL bằng hắc châm. VL chộp lấy, xóa ký ấn tinh thần của nàng — nàng ộc máu. VL bí mật cắm vào hắc châm một ký ấn trì hoãn: nếu không được giải trong 1 tháng, nàng sẽ chết. (@c0119)"},{"chuong":"@c0123","importance":"normal","text":"Bị Chu Tử Hồng đặt vào danh sách hai người VL phải giết (cùng Chu An) để đổi lấy tấm bản đồ. VL tìm tới thì thấy nàng đang ở chỗ hẻo lánh sau núi cùng Chu An; hắn lưu một tia thần thức trên Chu An rồi rời đi. (@c0123)"}],"tuVi":"Không rõ cụ thể; tu Chiến Thần Quyết — công pháp đặc biệt giữ dung nhan @c0103.","tuViMoc":[],"nhanMach":[{"ten":"Mã Lương (Vương Lâm)","quanHe":"Hôn thê cũ (đã thay lòng)","ghiChu":"Từng đính hôn, hứa làm lữ tu bạn; nay muốn Mã Lương đã chết và có tình lang mới @c0109. Tập kích VL bằng hắc châm @c0119 — bị VL cắm ký ấn chết chậm; nằm trong danh sách VL phải giết theo giao kèo với Chu Tử Hồng @c0123.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0103","@c0109","@c0110","@c0119","@c0123"]},{"id":"ba-thon-hon","name":"Ba Thôn Hồn","cn":"","aliases":["ba người hàng xóm","hàng xóm"],"gioiTinh":"khong-ro","theLuc":["Khe nứt không gian (Vực Ngoại)"],"canhGioiCaoNhat":"Thôn hồn (cấp trên du hồn)","trangThai":"hiện-dien (trong thần thức Vương Lâm @c0102–@c0106)","vaiTro":"Nhân vật phụ bí ẩn — nguồn thông tin về thế giới khe nứt","tinhCach":"Nhẫn nhịn, cẩn thận — tự nhận là 'hàng xóm'; trao đổi thông tin thực dụng vì lợi ích chung; hướng về mục tiêu trở về không gian tịch diệt","blurb":"Ba thực thể thôn hồn trú trong thần thức Vương Lâm khi VL còn ở khe nứt không gian. Chúng giải thích bản chất du hồn và hệ sinh thái khe nứt, đồng thời thực hiện nhiệm vụ dò tìm người theo lệnh VL. Xuất hiện trong khoảng @c0102–@c0106.","tabs":{"diem":[{"text":"Được VL gặp và gọi là 'hàng xóm' khi VL đang ở trong khe nứt không gian","chuong":"@c0102"},{"text":"Được VL sai đi tìm Hứa Hạo và Cát Dương, trở về báo cả hai đã tử vong","chuong":"@c0105"},{"text":"Giải thích hệ sinh thái khe nứt: du hồn là nô lệ/thức ăn của thôn hồn, 'ma đầu' là du hồn trong không gian","chuong":"@c0106"}],"kinhLich":[{"chuong":"@c0102","importance":"normal","text":"VL gặp ba thôn hồn (lúc VL đang trong khe nứt không gian). Đây là các thực thể VL sau đó gọi là 'hàng xóm'. (@c0102)"},{"chuong":"@c0105","importance":"normal","text":"Được VL sai đi tìm Hứa Hạo và Cát Dương; trở về báo cả hai đã tử vong. (@c0105)"},{"chuong":"@c0106","importance":"major","text":"Giải thích cho VL hệ sinh thái khe nứt: du hồn = nô lệ/thức ăn của thôn hồn; 'ma đầu' = du hồn trong không gian sinh linh; chiến trường ngoại vực = vùng đệm giữa không gian sinh linh và không gian tịch diệt. Cảnh báo VL cuối cùng phải trở về tịch diệt — VL ngơ ngác thất thần. (@c0106)"}],"tuVi":"Thôn hồn — cấp trên du hồn trong hệ sinh thái khe nứt @c0106.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Chủ nhân tạm thời / 'hàng xóm'","ghiChu":"Trú trong thần thức VL; trao đổi thông tin; cùng qua truyền tống trận @c0106.","tag":"lien-he"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0102","@c0105","@c0106"]},{"id":"hua-lap-quoc","name":"Hứa Lập Quốc","cn":"","aliases":["Kiếm Hồn","Lão nhị","Nhị sư huynh"],"gioiTinh":"nam","theLuc":[{"ten":"Thiên Cương Tông","trangThai":"da-roi"},{"ten":"Vương Lâm (ma đầu)","trangThai":"gan-bo"},{"ten":"Cự Ma tộc (giai đoạn bị lão tổ đoạt giữ tiên kiếm)","trangThai":"da-roi"}],"canhGioiCaoNhat":"Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan (@c0112) — ý thức gốc đã bị hủy, chỉ còn nguyên thần làm công cụ của VL","trangThai":"song — ẩn trong đám du hồn của Vương Lâm @c0280","vaiTro":"Ma đầu bị Vương Lâm khống chế — kiếm hồn, kiếm linh đời thứ nhất của Vũ tiên kiếm","tinhCach":"Kiêu ngạo hay lải nhải, thường xuyên đòi đảo ngược thân phận chủ tớ; thực dụng biết tự bảo toàn, dao động giữa phản chủ và lập công tùy tình thế; si mê nữ sắc, dễ mất bình tĩnh trước mỹ nhân; bản tính nhát gan nhưng khi bị dồn ép có thể liều mạng","blurb":"Hứa Lập Quốc vốn là tu sĩ Nguyên Anh kỳ của Thiên Cương Tông, bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc và ép luyện nguyên thần thành Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan. Từ đó hắn trở thành ma đầu duy nhất được Vương Lâm giữ lại, lần lượt ẩn trong đám du hồn, nhập tiên kiếm làm kiếm hồn, rồi được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ mà trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm. Dù miệng liên tục đòi tự do và nhiều lần dao động ý phản chủ, Hứa Lập Quốc vẫn theo Vương Lâm xông pha vô số trận chiến, bị giam luyện trong lốc xoáy lửa ba năm khiến thực lực tăng m","tabs":{"diem":[{"text":"Bị Vương Lâm bắt sống tại Phần Kim sơn mạch, hủy ý thức gốc và ép luyện nguyên thần thành Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan","chuong":"@c0112"},{"text":"Kiệt sức cản đòn bảo vệ thân thể Vương Lâm trước người khổng lồ băng tuyết khi nguyên thần Vương Lâm rời thể","chuong":"@c0338"},{"text":"Phản chủ bẻ kiếm chém đứt cánh tay trái Cự Ma lão tổ rồi quay về theo Vương Lâm","chuong":"@c0373"},{"text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của Vũ tiên kiếm","chuong":"@c0596"},{"text":"Bị giam trong lốc xoáy lửa suốt ba năm, liên tục kháng cự khiến thực lực tăng mạnh","chuong":"@c1018"},{"text":"Thuần phục loan đao Lão Tứ tìm thấy ở Chu Tước mộ, thu nhận làm đồ bạn","chuong":"@c0440"}],"kinhLich":[{"chuong":"@c0111","importance":"normal","tieuDe":"Lộ diện tại Phần Kim sơn mạch","text":"Lộ diện tại Phần Kim sơn mạch sau khi VL diệt ba tay sai Thi Âm Tông. Vốn là Nguyên Anh kỳ Thiên Cương Tông — hiện đang mượn thân Trúc Cơ của Thi Âm Tông để hồi phục. (@c0111)"},{"chuong":"@c0112","importance":"major","tieuDe":"Bị VL tạo thành Ma Đầu","text":"Bị VL bắt sống. VL hủy ý thức rồi ép phần nguyên thần liên tục tiêu thụ hồn dã thú. Khi hào quang ám hồng hình thành, Ma Đầu ra đời — tu vi Trúc Cơ hậu kỳ đỉnh giả đan. Ý thức gốc diệt, chỉ còn công cụ nguyên thần phục vụ VL. (@c0112)"},{"bridge":true,"khoang":"@c0179–@c0253","text":"Được VL dùng thôn phệ thần thức Tiền Côn @c0179; làm tay sai giám sát Vân Phi @c0180. Là ma đầu duy nhất VL giữ lại khi phóng hết ma đầu tộc Đằng gia tự bạo để tạo sương đen cản bà lão áo trắng @c0253."},{"chuong":"@c0280","importance":"normal","tieuDe":"Ẩn trong du hồn — bình an vô sự","text":"Trà trộn vào đám hơn vạn du hồn VL triệu xuất trên bình đài sau khi thoát tiên giới. Bề ngoài giống du hồn nhưng hai mắt có tia linh động. Tự nhủ đắc ý: lão Tam, lão Tứ, lão Ngũ đều đã chết hết, chỉ mình còn bình yên; bên mình có nhiều 'du hồn tiền bối' nên sẽ rất an toàn. (@c0280)"},{"bridge":true,"khoang":"@c0318","text":"VL ném Hứa Lập Quốc vào tiên kiếm Cự Phú làm Kiếm Hồn tạm thời — du hồn nhập kiếm, giúp VL phi kiếm quanh thân 3 trượng mà không cần cầm tay. (@c0318)"},{"bridge":true,"khoang":"@c0324–@c0328","text":"Du hồn trong tiên kiếm kêu gào khi VL dùng tiên kiếm liên tiếp nhiều đòn — cảnh báo sử dụng quá nhiều sẽ tan thành mây khói. VL nắm vững phi kiếm không tay trong 8 tháng luyện pháp bảo. (@c0324, @c0328)"},{"chuong":"@c0338","importance":"major","tieuDe":"Cản đòn bảo vệ thân thể VL — kiệt sức","text":"Khi nguyên thần VL rời thể, thân thể VL bị người khổng lồ băng tuyết đánh xuống. VL gọi 'Hứa Lập Quốc!' — tiên kiếm phát hắc khí khống chế, cản 1 đòn nặng. Sau đó kêu yếu ớt, tiên kiếm rơi im — kiệt sức hoàn toàn. (@c0338)"},{"bridge":true,"khoang":"@c0339","text":"VL xuất linh lực giúp Hứa Lập Quốc hồi phục sau khi kiệt sức. (@c0339)"},{"importance":"normal","text":"Kiếm hồn trong tiên kiếm của Vương Lâm; khi VL bị Cự Ma lão tổ cướp tiên kiếm, hắn nằm trong kiếm dưới tay lão tổ, vẫn nhớ và oán VL từng sai khiến mình.","chuong":"@c0372"},{"importance":"normal","text":"Phản chủ: bẻ kiếm chém đứt cánh tay trái Cự Ma lão tổ rồi quay về theo Vương Lâm, xin VL cứu pháp hồn Phượng Loan.","chuong":"@c0373"},{"bridge":true,"khoang":"@c0459–@c0459","text":"Là khí linh trong tiên kiếm của Vương Lâm, được điều khiển cùng loan đao lao thử phá trận pháp khốn địa nhưng thất bại, kêu thảm rằng không phá nổi thứ này rồi bị thu về."},{"text":"Là nhị sư huynh Tử hệ Thiên Vận Tông, hóa tử quang nghênh chiến Vương Lâm, phóng Thượng chi lực hóa đám cát như bầy ong nhưng bị Cấm Phiên xé tan. Hắn dùng cấm thuật Tiên Ma thể hóa toàn thân thành sương mù đen để trốn, viện cớ hôm nay là đại thọ sư tôn, song bị tiên kiếm cùng loan đao chém tan, cuối cùng nguyên thần bị Côn Cực Tiên đánh trúng, trọng thương sắp tan.","bridge":true,"khoang":"@c0462"},{"text":"Bị nhốt trong kiếm tiên của Vương Lâm, Hứa Lập Quốc lên tiếng kiêu ngạo và cùng thanh loan đao đuổi theo, giam giữ lão già thấp người Trưởng lão Đại La Kiếm Tông đang bỏ chạy.","bridge":true,"khoang":"@c0483"},{"text":"Tồn tại như hồn/khí linh trong tiên kiếm của Vương Lâm. Khi Vương Lâm thả tiên kiếm bay ra trước cửa thứ sáu để chuẩn bị xông cung, bên trong kiếm truyền ra tiếng gầm rú liên tục của Hứa Lập Quốc.","bridge":true,"khoang":"@c0527"},{"text":"Si mê thiếu nữ Kiếm Linh (Đế Kiếm), Hứa Lập Quốc phá phong tỏa lải nhải đòi Vương Lâm thả ra tìm tiểu mỹ nhân, mắng Vương Lâm ghen tị. Hắn lén cùng Tiểu Hắc làm yếu cấm chế, biến thành hình kiếm phá cấm chế bỏ chạy ra khỏi Thiên Yêu Thành nhưng bị Vương Lâm dùng cấm chế kéo về, quỳ cầu xin và khai toàn bộ thần thông học từ Kiếm Linh.","bridge":true,"khoang":"@c0545"},{"text":"Khí linh cư ngụ trong tiên kiếm của Vương Lâm, từng làm phản thất bại nên cẩn thận. Lần này quyết lập công chuộc tội, điều tiên kiếm hóa kiếm long chém bộ xương cánh tay đen nhưng bị hộ uyển truyền ma khí bóp chặt, phải rút về thân kiếm. Cuối chương run sợ trước trạng thái cuồng ngạo của Vương Lâm, không dám nói tiếng nào.","bridge":true,"khoang":"@c0557"},{"bridge":true,"khoang":"@c0579","text":"Biến ảo ra từ pháp bảo của Vương Lâm, hiểu tâm ý chủ, quát thanh hắc đao Tiểu hắc tử lập tức đuổi theo cây Tiên bút mà lão già ném vào hư vô."},{"chuong":"@c0595","importance":"normal","tieuDe":"Thành kiếm linh viễn cổ của Vương Lâm","text":"Hứa Lập Quốc cảm nhận Chu Dật mới là kiếm linh chính thức của thanh kiếm mình ký sinh nên sinh lòng kính sợ, tỏ ra nhũn nhặn lấy lòng khiến Vương Lâm khó coi. Chu Dật chộp lấy hắn, truyền kiếm ý viễn cổ vào mắt, biến hắn thành kiếm linh chính thức phục vụ Vương Lâm, đồng thời cài một chút lạc ấn: nếu sau này phản bội Vương Lâm thì truyền thừa sẽ cắn trả."},{"chuong":"@c0596","importance":"major","tieuDe":"Trở thành kiếm linh đời thứ nhất","text":"Được Chu Dật cho lĩnh hội truyền thừa kiếm ý viễn cổ, trở thành kiếm linh đời thứ nhất của thanh Vũ tiên kiếm mà Chu Dật trao cho Vương Lâm; đang mê man trong truyền thừa thì được Vương Lâm thu vào kiếm tiên."},{"importance":"normal","chuong":"@c0376","tieuDe":"Bị Mị Cơ mê hoặc, mất tự chủ rồi bị Vương Lâm đánh tỉnh","text":"Hứa Lập Quốc hiện thân từ tiên kiếm, vừa thấy pháp luân liền mất tự chủ, cầu khẩn Vương Lâm thả hồn phách bên trong ra. Khi pháp luân bị phá, Mị Cơ xuất hiện dùng ý cảnh mê hoặc khiến gã hoàn toàn chìm trong dục vọng, thậm chí định đánh lén Vương Lâm từ phía sau. Vương Lâm điểm tay khiến gã bị thương, tỉnh táo lại, gã sợ hãi nhận ra mình suýt ra tay với \"sát tinh\", vội quay sang quát mắng Mị Cơ là tiện nhân mê hoặc.","anchor":"Chủ nhân không thể trách ta. Ta vừa nhìn pháp luân liền không khống chế được bản thân","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0377","tieuDe":"Nịnh nọt xin về, chui vào tiên kiếm trốn","text":"Hứa Lập Quốc đổi giọng nịnh nọt xin về trước, hóa khí đen chui vào tiên kiếm không dám ló mặt.","anchor":"Hứa Lập Quốc đổi giọng nịnh nọt xin về trước","mucCt":"gon","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0406","tieuDe":"Bị Mị Cơ áp chế, sợ hãi chui lại vào tiên kiếm","text":"Hứa Lập Quốc tách hồn phách ra khỏi tiên kiếm định gần gũi nữ tử thần bí, nhưng bị nàng điểm vào lông mày áp chế; hắn dùng kế hư ảnh hóa kiếm quang đánh lén song bị Mị Cơ thổi một hơi làm tiêu tan, sợ run chui lại vào tiên kiếm.","anchor":"tách ra định gần gũi nữ tử thì bị nàng điểm vào lông mày","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0420","tieuDe":"Hiện thân nhìn Mị Cơ với dục vọng","text":"Hứa Lập Quốc biến ảo từ kiếm tiên hiện ra, hai mắt phát dục vọng nhìn Mị Cơ khi nàng ngưng thật trong Hoạ trục.","anchor":"Hứa Lập Quốc biến ảo từ kiếm tiên hiện ra, hai mắt phát dục vọng nhìn Mị Cơ","mucCt":"gon","nguon":["bồi-cuối-quyển"]},{"importance":"normal","chuong":"@c0425","tieuDe":"Bị triệu hồi để mở đường giữa vùng kiếm hồn, nhát gan bỏ chạy","text":"Hứa Lập Quốc được Vương Lâm triệu hồi từ kiếm tiên để khắc chế các kiếm hồn trong vùng hố trũng, vừa xuất hiện thì vô số bảo kiếm e ngại mà tháo chạy về trung tâm. Tới gần trung tâm, hắn sợ không dám tiến, định trốn vào kiếm tiên nhưng bị Vương Lâm ném tới ép xông vào đám bảo kiếm. Khi loan đao xuất hiện đánh bật kiếm tiên ra mấy trượng, Hứa Lập Quốc nhát gan kéo kiếm tiên bỏ chạy về phía Vương Lâm.","anchor":"Hứa Lập Quốc — kiếm hồn nửa đường, hiện hình từ màn sương đen","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"normal","chuong":"@c0426","tieuDe":"Bị thanh loan đao cuốn đi mất","text":"Hứa Lập Quốc bị Vương Lâm dùng kiếm tiên đánh văng ra ngoài làm mồi nhử, lập tức bị thanh loan đao cuốn lấy biến mất. Nhờ tâm linh tương thông với Vương Lâm nên vẫn có thể định vị được vị trí, Vương Lâm hứa sau khi thu hồi mệnh hồn sẽ đi cứu hắn.","anchor":"Vương Lâm xuất kiếm tiên đánh văng Hứa Lập Quốc ra ngoài","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"normal","chuong":"@c0440","tieuDe":"Thuần phục loan đao Lão Tứ, dẫn đi dạo chơi","text":"Hứa Lập Quốc từ trong tiên kiếm hiện ra, đắc ý khoe đã thuần phục được loan đao \"Lão Tứ\" tìm thấy ở Chu Tước mộ. Loan đao hóa thành đồng tử mơ hồ diện mạo, miễn cưỡng truyền thần thức bái kiến. Nay hắn mạnh hơn trước nhiều lần, nếu không e ngại sống chết bị Vương Lâm nắm giữ thì đã sớm làm phản. Hứa Lập Quốc dẫn Lão Tứ ra ngoài dạo chơi, một đao một kiếm hóa cầu vồng bay biến mất chân trời.","anchor":"một đao một kiếm hóa cầu vồng bay biến mất chân trời","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0452","tieuDe":"Gầm rú điên cuồng trong tiên kiếm khi xuất chiến","text":"Khi Vương Lâm vỗ túi trữ vật triệu tiên kiếm ra chiến đấu, nguyên thần Hứa Lập Quốc bị trấn bên trong phát ra tiếng cười và gầm rú điên cuồng.","anchor":"bên trong có tiếng cười điên cuồng của Hứa Lập Quốc","mucCt":"gon","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0485","tieuDe":"Loan đao phát u mang xuyên đầu lão già theo tâm niệm Vương Lâm","text":"Hứa Lập Quốc cảm nhận tâm niệm của Vương Lâm, cộng hưởng khiến thanh loan đao phát u mang xuyên qua đầu lão già thấp người ra sau gáy, giết chết lão.","anchor":"Hứa Lập Quốc cảm nhận được, thanh loan đao phát u mang xuyên qua đầu lão già","mucCt":"gon","nguon":["bồi-cuối-quyển"]},{"importance":"normal","chuong":"@c0544","tieuDe":"Hứa Lập Quốc xin ra ngoài đuổi theo Kiếm Linh của Đế Kiếm","text":"Hứa Lập Quốc cảm nhận được thiếu nữ Kiếm Linh xinh đẹp của Đế Kiếm nhờ kỹ xảo học từ Tiểu Hắc Đao, kích động xin Vương Lâm thả ra ngoài. Hắn cười dâm đãng tự xưng \"Hứa gia gia\", lao tới tán tỉnh thiếu nữ Kiếm Linh, bị nàng đá kiếm khí nhưng tản thân hóa giải rồi tiếp tục rượt đuổi. Nhờ Tiểu Hắc hỗ trợ che giấu khí tức và tinh thần phấn khởi, hắn cân bằng được với thiếu nữ dù vốn không phải đối thủ, cho đến khi nàng quay về Kiếm Thể thì hắn tức giận gào sẽ lại tới.","anchor":"cười dâm đãng tự xưng Hứa gia gia","mucCt":"ky","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0561","tieuDe":"Huyễn hóa từ tiên kiếm, cứa đứt ngón tay lão già Địa Ma","text":"Hứa Lập Quốc huyễn hóa từ tiên kiếm, điều khiển kiếm cứa đứt ngón tay lão già khi hắn chộp tiên kiếm.","anchor":"huyễn hóa từ tiên kiếm, điều khiển kiếm cứa đứt ngón tay lão già","mucCt":"gon","nguon":["bồi-cuối-quyển"]},{"importance":"bridge","chuong":"@c0699","tieuDe":"Phát huy kiếm khí, kiếm ý hỗ trợ Trảm La Quyết diệt Hứa Phong Hàn","text":"Khi Vương Lâm thi triển Trảm La Quyết bằng tiên kiếm, Hứa Lập Quốc với tư cách kiếm linh bên trong đã phát huy tác dụng, khiến kiếm khí và kiếm ý viễn cổ tràn ngập.","anchor":"Hứa Lập Quốc phát huy tác dụng, khiến kiếm khí và kiếm ý viễn cổ tràn ngập","mucCt":"gon","nguon":["bồi-cuối-quyển"]}],"tuVi":"Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan (ý thức gốc Nguyên Anh kỳ đã bị hủy) @c0112. Nay tồn tại dưới dạng Kiếm Hồn trong tiên kiếm VL.","tuViMoc":[],"nhanMach":[{"ten":"Vương Lâm","gap":"@c0112","quanHe":"Chủ nhân (ma đầu → Kiếm Hồn)","ghiChu":"VL tạo Hứa Lập Quốc thành ma đầu; sau đó ném vào tiên kiếm @c0318. Lần đầu chủ động bảo vệ thân VL @c0338 — cản 1 đòn rồi kiệt sức.","tag":"phu-thuoc"},{"ten":"Vương Lâm","tag":"cap-tren","quanHe":"Chủ tử","ghiChu":"Gọi Vương Lâm là Chủ tử, được sai phá vây bất thành."},{"ten":"Vương Lâm","tag":"doi-thu","quanHe":"Bị Vương Lâm truy sát, đả thương nguyên thần giữa thọ yến","ghiChu":""},{"ten":"Triệu Tinh Sát","tag":"khac","quanHe":"Đồng môn Tử hệ đứng nhìn không cứu khi hắn bị giết","ghiChu":""},{"ten":"Tiểu Hắc (Tiểu Hắc Đao)","tag":"dong-minh","quanHe":"Cùng giao lưu, học thần thông Kiếm Linh; sau khi bị thu phục, loan đao đi theo bên cạnh hắn","ghiChu":"@c0545"},{"ten":"Đế Kiếm (thiếu nữ Kiếm Linh)","tag":"khac","quanHe":"Si mê gọi là “tiểu mỹ nhân”; bị Đế Kiếm thề chém nếu gặp lại","ghiChu":"@c0545"},{"ten":"Vương Lâm","tag":"dong-minh","quanHe":"Chủ nhân tiên kiếm nơi Hứa Lập Quốc cư ngụ; Hứa Lập Quốc nghe lệnh điều khiển kiếm.","ghiChu":"@c0557"},{"ten":"Tiểu hắc tử","tag":"dong-minh","quanHe":"Sai khiến Tiểu hắc tử (hắc đao) đuổi theo Tiên bút","ghiChu":"@c0579"},{"ten":"Chu Dật","tag":"khac","quanHe":"Kiếm linh chính thức truyền thừa cho mình","ghiChu":"Chu Dật truyền kiếm ý viễn cổ, cảnh báo Hứa Lập Quốc dễ thay đổi và cài lạc ấn."},{"ten":"Vương Lâm","tag":"khac","quanHe":"Chủ nhân mới","ghiChu":"Hứa Lập Quốc trở thành kiếm linh phục vụ Vương Lâm."}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0111","@c0112","@c0179","@c0253","@c0280","@c0318","@c0324","@c0328","@c0338","@c0339","@c0372","@c0373","@c0459","@c0462","@c0483","@c0527","@c0545","@c0557","@c0562","@c0579","@c0595","@c0596"]},{"id":"ton-huu-tai","name":"Tôn Hữu Tài","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Tà Ma Tông","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ (@c0113)","trangThai":"tu-vong (tự thiêu trong dung nham @c0115)","vaiTro":"Nhân vật phụ — đối thủ; tu sĩ Tà Ma Tông","tinhCach":"Xảo quyệt — vờ thân thiện để lên kế hoạch tập kích; thực dụng, bám theo người lạ tìm cơ hội; hèn nhát, bỏ trốn ngay khi thấy bất lợi","blurb":"Tôn Hữu Tài là tu sĩ Tà Ma Tông cảnh giới Trúc Cơ hậu kỳ. Từ khi gặp nhóm VL (Mã Lương) và Lý Kỳ Khánh, hắn vờ thân thiện rồi dẫn VL vào bẫy để Tứ sư huynh hắc y ra tay. Sau khi Tứ sư huynh bị VL giết chỉ bằng một chữ 'Diệt', hắn bỏ chạy vào miệng núi lửa và tự thiêu trong dung nham để trốn thoát, để lại túi trữ vật bị VL thu giữ.","tabs":{"diem":[{"text":"Tu vi Trúc Cơ hậu kỳ, xác nhận khi gặp VL","chuong":"@c0113"},{"text":"Vờ thân thiện, bám theo nhóm VL và Lý Kỳ Khánh để lên kế hoạch tập kích","chuong":"@c0113"},{"text":"Dẫn VL vào khu vực biệt lập, để Tứ sư huynh hắc y ra tay","chuong":"@c0114"},{"text":"Chứng kiến VL giết Tứ sư huynh chỉ bằng một chữ 'Diệt'","chuong":"@c0114"},{"text":"Chạy vào miệng núi lửa, tự thiêu trong dung nham để trốn thoát; VL kịp thu túi trữ vật","chuong":"@c0115"}],"kinhLich":[{"chuong":"@c0113","importance":"normal","text":"Bám theo nhóm VL + Lý Kỳ Khánh; vờ thân thiện, thực ra đang lên kế hoạch tập kích. (@c0113)"},{"chuong":"@c0114","importance":"major","text":"Dẫn VL vào khu vực biệt lập, để Tứ sư huynh hắc y ra tay. Khi VL giết Tứ sư huynh chỉ bằng một chữ 'Diệt', lập tức độn thổ bỏ chạy. (@c0114)"},{"chuong":"@c0115","importance":"major","text":"Chạy vào miệng núi lửa, tự thiêu trong dung nham để trốn thoát. VL kịp thu túi trữ vật trước khi hắn chết. (@c0115)"}],"tuVi":"Trúc Cơ hậu kỳ @c0113.","tuViMoc":[{"chuong":"@c0113","canhGioi":"Trúc Cơ hậu kỳ","text":"Xác nhận khi gặp VL @c0113."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0113","@c0114","@c0115"]},{"id":"tu-su-huynh-hac-y","name":"Tứ sư huynh hắc y","cn":"","aliases":["Tứ sư huynh"],"gioiTinh":"nam","theLuc":["Tà Ma Tông","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Trúc Cơ Đại viên mãn giả đan (@c0114)","trangThai":"tu-vong (bị VL giết bằng Thần Thức Cực Cảnh @c0114)","vaiTro":"Nhân vật phụ — đối thủ, đệ tử Tà Ma Tông","tinhCach":"Mưu tính giăng bẫy phối hợp đồng bọn; tự tin thi triển tà thuật","blurb":"Đệ tử Tà Ma Tông, tu vi Trúc Cơ Đại viên mãn giả đan. Cùng Tôn Hữu Tài giăng bẫy phục kích VL nhằm bắt làm khôi lỗi, thi triển Quỷ Hỏa Khô Lâu nhưng bị VL thốt một chữ 'Diệt' bằng Thần Thức Cực Cảnh — chết ngay tức thì, phi kiếm đen bị VL thu.","tabs":{"diem":[{"text":"Tu vi Trúc Cơ Đại viên mãn giả đan","chuong":"@c0114"},{"text":"Cùng Tôn Hữu Tài giăng bẫy phục kích VL để bắt làm khôi lỗi","chuong":"@c0114"},{"text":"Thi triển tà thuật Quỷ Hỏa Khô Lâu khi giao đấu","chuong":"@c0114"},{"text":"Bị VL giết tức thì bằng một chữ 'Diệt' (Thần Thức Cực Cảnh), phi kiếm đen bị thu","chuong":"@c0114"}],"kinhLich":[{"chuong":"@c0114","importance":"major","text":"Phục kích VL tại khu vực bẫy do Tôn Hữu Tài dẫn đến, thi triển Quỷ Hỏa Khô Lâu. VL thốt chữ 'Diệt' — Thần Thức Cực Cảnh tiêu diệt tức thì. VL thu phi kiếm đen. (@c0114)"}],"tuVi":"Trúc Cơ Đại viên mãn giả đan @c0114.","tuViMoc":[{"chuong":"@c0114","canhGioi":"Trúc Cơ Đại viên mãn giả đan","text":"Xác nhận khi xuất hiện @c0114."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0114"]},{"id":"phuong-loan","name":"Phượng Loan","cn":"","aliases":["bào y lam (mỹ phụ)","Phượng Loan lão tổ"],"gioiTinh":"nu","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Nguyên Anh sơ kỳ (@c0119)","trangThai":"song","vaiTro":"Nhân vật quan trọng — lão tổ Chiến Thần Điện, sư tổ bảo hộ VL","tinhCach":"Quyết đoán, dám chặn Nguyên Anh đồng cấp để bảo vệ đệ tử; trọng ân nghĩa, đáp ơn người cứu thân nhân; thâm trầm, tinh ý dò xét tu vi bất thường của người dưới","blurb":"Phượng Loan là lão tổ Nguyên Anh sơ kỳ của Chiến Thần Điện và là sư tổ của Chu Tử Hồng ('Hồng nhi'). Bà xuất hiện lần đầu dưới thân phận thiếu phụ cung trang tới nhận lại bản mệnh tinh huyết của Chu Tử Hồng từ VL, rồi chính thức lộ danh và thu VL làm ký danh đệ tử để đáp ơn. Tính tới thời điểm mới nhất, bà đã ra tay chặn Chu Cẩn cứu VL và bắt đầu dò xét biểu hiện tu vi bất thường của hắn.","tabs":{"diem":[{"text":"Xuất hiện dưới thân phận thiếu phụ cung trang, nhận lại bản mệnh tinh huyết Chu Tử Hồng từ VL","chuong":"@c0113"},{"text":"Tại cuộc họp 6 lão Nguyên Anh 4 tông, tiết lộ điểm yếu hàn thuộc tính của hỏa linh thú","chuong":"@c0117"},{"text":"Lộ danh Phượng Loan (Nguyên Anh sơ kỳ), bắt Lâm Đào và chặn Chu Cẩn để cứu VL","chuong":"@c0119"},{"text":"Gọi VL tới lầu các, dò hỏi vì sao tu vi chỉ thể hiện Trúc Cơ trung kỳ và trao ngọc giản","chuong":"@c0121"},{"text":"Được nhắc lại qua lời nam tử áo tím về các nữ nhân lợi hại ở Phượng Loan tinh","chuong":"@c0908"}],"kinhLich":[{"chuong":"@c0113","importance":"normal","text":"Xuất hiện (chưa nêu tên, là thiếu phụ cung trang) nhận lại bản mệnh tinh huyết Chu Tử Hồng từ VL (thân Mã Lương), hứa che giấu việc VL đoạt xá để đáp ơn cứu 'Hồng nhi'. (@c0113)"},{"chuong":"@c0117","importance":"normal","text":"Tại cuộc họp 6 lão Nguyên Anh 4 tông, tiết lộ thông tin cốt lõi: điểm yếu của hỏa linh thú là hàn thuộc tính pháp thuật. (@c0117)"},{"chuong":"@c0119","importance":"major","text":"Lộ danh là Phượng Loan. Bắt Lâm Đào khi sao chép địa đồ. Chu Cẩn (Nguyên Anh sơ kỳ) xông ra định giết VL — Phượng Loan chặn bằng Ngũ thải phượng xa. Chính thức thu VL làm ký danh đệ tử — bảo hộ VL dưới danh nghĩa sư môn Chiến Thần Điện. (@c0119)"},{"chuong":"@c0121","importance":"normal","text":"Trước khi VL xuất chinh, gọi hắn tới lầu các, dò hỏi vì sao tu vi chỉ thể hiện Trúc Cơ trung kỳ. Trao ngọc giản bản đồ Hỏa Phần quốc (ba phần) kèm giao kèo: giết 50 Trúc Cơ → thêm một phần, giết 150 → phần cuối. Vì ơn cứu Hồng nhi nên có nhân tình, muốn ngăn VL đoạt xá. (@c0121)"}],"tuVi":"Nguyên Anh sơ kỳ @c0113.","tuViMoc":[{"chuong":"@c0119","canhGioi":"Nguyên Anh sơ kỳ","text":"Xác nhận Nguyên Anh sơ kỳ khi lộ danh trên ngũ thải phượng xa @c0119 (tương đương Chu Cẩn)."}],"nhanMach":[{"ten":"Dương Sâm","quanHe":"Đạo lữ song tu","ghiChu":"Nguyên Anh trung kỳ, Chiến Thần Điện @c0119.","tag":"than-thiet"},{"ten":"Chu Tử Hồng","quanHe":"Sư tổ / người thân","ghiChu":"Sư tổ và người thân của Chu Tử Hồng ('Hồng nhi'); nhận VL ký danh để đáp ơn cứu Hồng nhi @c0119.","tag":"su-mon"},{"ten":"Vương Lâm","quanHe":"Ký danh đệ tử","ghiChu":"Thu VL làm ký danh đệ tử @c0119.","tag":"su-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0113","@c0117","@c0119","@c0121"]},{"id":"duong-sam","name":"Dương Sâm","cn":"","aliases":["trung niên văn sĩ"],"gioiTinh":"nam","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Nguyên Anh trung kỳ (@c0119); đỉnh kỳ @c0120","trangThai":"song","vaiTro":"Nhân vật quan trọng — đạo lữ song tu của Phượng Loan, lão tổ Chiến Thần Điện","tinhCach":"Lịch sự, trọng lễ — đích thân cúi chào VL sau khi Phượng Loan thu VL làm đệ tử; hào phóng, tặng ngọc phù bảo mệnh cấp Nguyên Anh quý giá; quyết đoán trong chiến trận","blurb":"Lão tổ Nguyên Anh trung kỳ đỉnh của Chiến Thần Điện, đạo lữ song tu của Phượng Loan. Lần đầu xuất hiện tại @c0119, cúi chào VL và tặng ngọc phù bảo mệnh cấp Nguyên Anh. Đến @c0120, đích thân dẫn đại quân vào Tuyên Vũ quốc và giết lão bà Nguyên Anh sơ kỳ của địch.","tabs":{"diem":[{"text":"Đạo lữ song tu của Phượng Loan, lão tổ Chiến Thần Điện","chuong":"@c0119"},{"text":"Cúi chào VL và tặng ngọc phù bảo mệnh cấp Nguyên Anh làm bảo vật phòng thân","chuong":"@c0119"},{"text":"Tu vi Nguyên Anh trung kỳ khi xuất hiện, sau xác nhận đạt Nguyên Anh trung kỳ đỉnh","chuong":"@c0120"},{"text":"Đích thân dẫn đại quân vào Tuyên Vũ quốc, giết lão bà Nguyên Anh sơ kỳ của địch","chuong":"@c0120"}],"kinhLich":[{"chuong":"@c0119","importance":"major","text":"Xuất hiện cùng Phượng Loan. Cúi chào VL, tặng ngọc phù bảo mệnh cấp Nguyên Anh — bảo vật quý phụ trợ phòng thân. (@c0119)"},{"chuong":"@c0120","importance":"normal","text":"Đích thân dẫn đại quân vào Tuyên Vũ quốc. Giết lão bà (Nguyên Anh sơ kỳ) của Tuyên Vũ quốc trong đợt tấn công đầu tiên. (@c0120)"}],"tuVi":"Nguyên Anh trung kỳ đỉnh @c0120.","tuViMoc":[{"chuong":"@c0119","canhGioi":"Nguyên Anh trung kỳ","text":"Xác nhận khi xuất hiện @c0119."},{"chuong":"@c0120","canhGioi":"Nguyên Anh trung kỳ đỉnh","text":"Xác nhận cụ thể hơn @c0120."}],"nhanMach":[{"ten":"Phượng Loan","quanHe":"Đạo lữ song tu","ghiChu":"Nguyên Anh sơ kỳ, Chiến Thần Điện @c0119.","tag":"than-thiet"},{"ten":"Vương Lâm","quanHe":"Đệ tử ký danh của đạo lữ","ghiChu":"Cúi chào và tặng ngọc phù bảo mệnh @c0119.","tag":"ban-be"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0119","@c0120"]},{"id":"chu-can","name":"Chu Cẩn","cn":"","aliases":["trung niên văn sĩ"],"gioiTinh":"nam","theLuc":["Chiến Thần Điện","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Nguyên Anh sơ kỳ (@c0119)","trangThai":"song","vaiTro":"Nhân vật phụ — quan viên quân vụ cùng phe Phượng Loan","tinhCach":"Nghiêm khắc, đa nghi — tra hỏi gắt gao việc tu vi tăng nhanh bất thường; ban đầu thù địch VL rồi chuyển sang phối hợp dưới trướng Phượng Loan.","blurb":"Tu sĩ Nguyên Anh sơ kỳ Hỏa Phần quốc, dáng trung niên văn sĩ, cùng phe Phượng Loan trong Chiến Thần Điện. Từng xông ra định giết VL @c0119 (bị Phượng Loan chặn), sau đó phụ trách chấm chiến công và tra hỏi VL về việc tăng tu vi @c0122.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0119","importance":"minor","text":"Nhân lúc hỗn loạn, xông ra định tấn công và giết VL. Bị Phượng Loan can thiệp bằng Ngũ thải phượng xa, buộc phải dừng. (@c0119)"},{"chuong":"@c0122","importance":"normal","text":"Tại Thiên Điện, chấm chiến công cho VL (61 Trúc Cơ + 1 Kết Đan), nghiêm khắc tra hỏi vì sao VL tăng tu vi nhanh và giết được Kết Đan kỳ; dò ra dư linh lực Kim Đan nên tin lời ngụy báo. Báo tin Tuyên Vũ quốc đã liên hợp, sắp đại chiến. (@c0122)"}],"tuVi":"Nguyên Anh sơ kỳ @c0119.","tuViMoc":[{"chuong":"@c0119","canhGioi":"Nguyên Anh sơ kỳ","text":"Xác nhận khi xuất hiện @c0119."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0119","@c0122"]},{"id":"dieu-linh","name":"Diệu Linh","cn":"","aliases":[],"gioiTinh":"khong-ro","theLuc":["Hỏa Phần Quốc"],"canhGioiCaoNhat":"Nguyên Anh kỳ (@c0118)","trangThai":"song","vaiTro":"Nhân vật phụ","tinhCach":"Thận trọng — chặn VL hỏi thăm thay vì tấn công trực tiếp.","blurb":"Tu sĩ Nguyên Anh kỳ Hỏa Phần quốc. Chặn đường VL trong trận đại quân 10.000 tu sĩ để thẩm vấn. (@c0118)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0118","importance":"minor","text":"Chặn VL giữa đại quân hơn 10.000 tu sĩ, hỏi thăm danh tính và mục đích. (@c0118)"}],"tuVi":"Nguyên Anh kỳ @c0118.","tuViMoc":[{"chuong":"@c0118","canhGioi":"Nguyên Anh kỳ","text":"Xác nhận khi xuất hiện @c0118."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0118"]},{"id":"ly-ky-khanh","name":"Lý Kỳ Khánh","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Lạc Hà Môn","Hỏa Phần Quốc"],"canhGioiCaoNhat":"Trúc Cơ hậu kỳ giả đan (@c0113)","trangThai":"song","vaiTro":"Nhân vật phụ","tinhCach":"Nhiệt tình, thiện ý — mời người mới tham dự đại hội phương thị.","blurb":"Tu sĩ nam Lạc Hà Môn, mặt trắng như ngọc, trường bào tím, phi kiếm xanh biếc; Trúc Cơ hậu kỳ đã tiến giả đan. Cùng sư muội Uyển Nhi truy tìm một kẻ giỏi thuật dịch dung, thoạt nhầm VL (tên Mã Lương) là kẻ đó rồi giải hiềm; mời VL tham dự Khê Cốc phường thị đại hội. (@c0113)","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0113","importance":"minor","text":"Cùng sư muội Uyển Nhi truy tìm kẻ giỏi thuật dịch dung; thoạt nhầm VL (Mã Lương) là kẻ đó, được Uyển Nhi phân biệt qua khí chất nên giải hiềm. Mời VL tham dự Khê Cốc phường thị đại hội. (@c0113)"}],"tuVi":"Trúc Cơ hậu kỳ giả đan @c0113.","tuViMoc":[{"chuong":"@c0113","canhGioi":"Trúc Cơ hậu kỳ giả đan","text":"Xác nhận khi xuất hiện @c0113."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0113"]},{"id":"hoa-linh-thu-to","name":"Hỏa Linh Thú tổ","cn":"","aliases":["Thú tổ hỏa linh"],"gioiTinh":"khong-ro","theLuc":[],"canhGioiCaoNhat":"Không xác định (dã thú thần thú sơn mạch @c0116)","trangThai":"bi-thu-phuc (bị Nghịch Thiên Châu hấp thu nguyên anh hỏa thuộc tính @c0116)","vaiTro":"Nhân vật phụ — thú tổ bầy hỏa linh thú, nguồn năng lượng","tinhCach":"Hung hãn; thống lĩnh bầy hỏa linh thú trong miệng núi lửa","blurb":"Thú tổ của bầy hỏa linh thú cư ngụ tại miệng núi lửa Phần Kim sơn mạch. Khi Nghịch Thiên Châu tự phá ra khỏi huyệt đạo, nguyên anh hỏa thuộc tính của Thú tổ bị hấp thu — sự kiện then chốt giúp Nghịch Thiên Châu đạt hỏa thuộc tính Đại viên mãn.","tabs":{"diem":[{"text":"Thú tổ cai trị bầy hỏa linh thú tại miệng núi lửa Phần Kim sơn mạch","chuong":"@c0116"},{"text":"Nguyên anh hỏa thuộc tính bị Nghịch Thiên Châu hấp thu khi tự phá huyệt đạo","chuong":"@c0116"},{"text":"Sự hấp thu này là mấu chốt giúp Nghịch Thiên Châu đạt hỏa thuộc tính Đại viên mãn","chuong":"@c0116"}],"kinhLich":[{"chuong":"@c0116","importance":"major","text":"Nghịch Thiên Châu tự phá ra khỏi huyệt đạo VL, hấp thu nguyên anh hỏa thuộc tính của Thú tổ. Sau khi hấp thu xong, bầy hỏa linh thú vỡ tán, các hỏa linh thú nhỏ hoảng loạn. (@c0116)"}],"tuVi":"Không xác định @c0116.","tuViMoc":[],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0116"]},{"id":"ly-mo-uyen","name":"Lý Mộ Uyển","cn":"","aliases":["Lý Mộc Uyển"],"gioiTinh":"nu","theLuc":["Lạc Hà Môn"],"canhGioiCaoNhat":"Kết Đan hậu kỳ — 3 lần Kết Anh thất bại; tuổi thọ sắp cạn @c0302; đang được VL điều trị @c0306; thân xác hóa xương khô, nguyên anh đầu thai @c0313","trangThai":"chuyen-sinh — nguyên anh đầu thai thành bé gái Chu Như tại Hạnh Hoa Thôn @c0313","vaiTro":"Nhân vật nữ chính — người yêu Vương Lâm, thiên tài luyện đan và trận pháp","tinhCach":"Tài hoa xuất chúng về luyện đan và trận pháp; kiên cường chịu đựng trước suy kiệt kéo dài và cái chết cận kề; nặng tình với Vương Lâm dù biết duyên phận mong manh; giàu lòng trắc ẩn và tự hy sinh — sẵn sàng từ bỏ cơ hội tái sinh để cứu Chu Như","blurb":"Lý Mộ Uyển là tu sĩ Kết Đan hậu kỳ có thiên phú luyện đan và trận pháp hiếm thấy, từng bị Song Tu Môn truy sát vì Thiên Ly đan rồi được Vương Lâm cứu, hai người đồng hành bốn năm tại Tu Ma Hải và khắc sâu tình cảm trước khi chia cách. Hơn trăm năm sau, ba lần Kết Anh thất bại khiến tuổi thọ cạn kiệt; dù Vương Lâm tìm mọi cách điều trị, thân xác bà vẫn hóa xương khô, nguyên anh được dùng bức tranh sinh tử luân hồi đưa vào chuyển sinh thành bé gái Chu Như tại Hạnh Hoa Thôn, rồi sau chín mươi năm im lặng bà thức tỉnh và tự đẩy nguyên anh ra khỏi thân thể Chu Như để cứu đứa trẻ. Nguyên anh sau đó ","tabs":{"diem":[{"text":"Bốn năm đồng hành cùng Vương Lâm tại Tu Ma Hải, khắc 18.974 ngọc giản đan phương, rồi chia tay trao lại bản mệnh tinh huyết","chuong":"@c0137"},{"text":"Ba lần Kết Anh thất bại, tuổi thọ cạn kiệt, ngồi đánh đàn tại Đông Uyển Các với dung nhan tang thương","chuong":"@c0302"},{"text":"Thân xác hóa xương khô, kim đan nứt vỡ; Vương Lâm dùng bức tranh sinh tử luân hồi đưa nguyên anh đầu thai","chuong":"@c0313"},{"text":"Thức tỉnh trong thân Chu Như sau chín mươi năm, từ chối cắn nuốt hồn phách và tự đẩy nguyên anh ra để cứu đứa trẻ","chuong":"@c0381"},{"text":"Nguyên anh được Vương Lâm giữ gìn gần bảy trăm năm, đưa ra trước Lôi Tiên điện cầu cứu; bị chẩn đoán tử vong nhưng còn tia hy vọng Thất Tịch Thuật","chuong":"@c0827"},{"text":"Được Vương Lâm coi là chiếc vảy nghịch thật sự của cả đời, quan trọng hơn Thiên Nghịch hay thần thức Cổ Thần","chuong":"@c1205"}],"kinhLich":[{"chuong":"@c0123","importance":"normal","text":"Bị một trưởng lão Song Tu Môn (Kết Đan trung kỳ) truy sát để cướp Thiên Ly đan; tiểu đội 13 người đã bị giết. Được Vương Lâm cứu, mang theo lánh vào Tu Ma Hải."},{"chuong":"@c0124","importance":"major","text":"Chứng kiến Vương Lâm dùng Tử Chú thuật giết ba tu sĩ Đấu Tà phái; nhận ra hắn chính là kẻ khiến hơn nửa Trúc Cơ kỳ Tuyên Vũ quốc tử trận. Bố Cửu Ly Thi Cốt trận cho động phủ và giao bản mệnh tinh huyết, đổi lấy việc luyện đủ đan cho Vương Lâm trước khi hắn kết đan, sau đó được đưa rời Tu Ma Hải."},{"chuong":"@c0126","importance":"normal","text":"Lột da giao long chế hai bộ nội giáp, dùng giao long cốt nâng trận thành Cửu Ly Giao Long trận; lập phòng luyện đan, trồng linh thảo trong động phủ."},{"chuong":"@c0127","importance":"major","text":"Khi động phủ bị mười Kết Đan kỳ Đấu Tà phái công phá, dùng Bách Thú Linh Lô và Ma Huyết đằng luyện thành công Thiên Ly đan (lần hai), kịp giúp Vương Lâm kết đan."},{"chuong":"@c0130","importance":"minor","text":"Theo Vương Lâm trong cuộc truy diệt Đấu Tà phái; nhận ra hắn là 'người vô tình' nhưng vẫn thấy yên lòng bên hắn. Vương Lâm hứa đưa nàng tới Hỏa Phần Minh sau khi xong việc."},{"chuong":"@c0135","importance":"normal","text":"Trong bốn năm đồng hành tại Tu Ma Hải, đã khắc 18.974 ngọc giản luyện đan — bộ sưu tập đan phương khổng lồ. Vương Lâm quyết định đưa nàng rời Tu Ma Hải."},{"chuong":"@c0136","importance":"minor","text":"Được Vương Lâm mang chạy trốn lão nhân thanh bào trong Tu Ma Hải, lặn biển và vọt lên không."},{"chuong":"@c0137","importance":"major","text":"Chia tay Vương Lâm sau bốn năm đồng hành: nhận lại bản mệnh tinh huyết (kèm thần thức hộ thể của VL); tặng hơn mười bình đan dược, ngọc giản ghi đan phương, ngọc phù Đấu Long trận cải biến và một ngọc giản phòng ngự (chứa hư ảnh Thanh Long) để dùng khi bế quan; nhận lại Bách Thú Linh Lô. Tiết lộ hai người chưa từng biết tên thật của nhau, rồi đạp kiếm quang bay về Hỏa Phần Minh."},{"chuong":"@c0149","importance":"minor","text":"Nhắc qua hồi tưởng: từng dặn Vương Lâm về dịch tủy giao long (phần quý nhất, có thể tăng tỷ lệ kết anh) và về hai loại đan trợ Kết Anh; ngọc giản Thanh Long nàng để lại cứu mạng VL trong Cổ Thần Chi Địa (@c0147, @c0149)."},{"chuong":"@c0302","importance":"major","tieuDe":"Ngọn đèn tàn — 3 lần Kết Anh thất bại, sống không quá 10 năm","text":"Ngồi đánh đàn tại Đông Uyển Các, dung nhan tang thương, tóc sắp bạc. Sống nhờ lộ thủy hạt châu nghịch thiên nhưng hiệu quả mất dần. Tu vi dừng ở Kết Đan hậu kỳ — 3 lần Kết Anh thất bại; nếu 10 năm tới không Kết Anh sẽ chết. Tiếng đàn lộ ý tử vong. Gọi nhỏ 'Vương đại ca'. (@c0302)"},{"bridge":true,"khoang":"@c0303–@c0304","text":"Suy kiệt tiếp diễn: ho ra máu, thân thể già đi, nhận ra tuổi thọ đang hết. Quyết trả hồn huyết cho Liễu Phỉ + Tống Thanh, kiên quyết ở lại Vân Thiên Tông chờ VL vì đây là nơi ước định giữa hai người. Hồn thú từ mi tâm xuất chiến khi Triển Bạch bắn huyết trùng — nuốt hết. Tuyệt vọng thì thầm 'Vương đại ca, kiếp sau hẹn gặp lại' đúng lúc VL xuất hiện. (@c0303–@c0304)"},{"chuong":"@c0305","importance":"major","tieuDe":"Tái hội ngộ Vương Lâm","text":"Nhận ra VL dù diện mạo đã khác, hai hàng lệ xối xả, gọi tên 'Vương Lâm'. Chứng kiến VL đại chiến và giết Triển Bạch. (@c0305)"},{"bridge":true,"khoang":"@c0306–@c0308","text":"Được VL điều trị liên tục — tần suất tăng từ 1 ngày/lần lên 2 ngày/3 lần, tử khí càng đậm. Nhận phương thuốc ngũ phẩm linh đan VL tặng. Cùng VL về Tu Ma hải, thăm động phủ cũ nay hoang tàn; VL nâng núi tạo lại động phủ — tử khí phai nhạt vì vui. Những ngày này là vui nhất ngoài thời ở Lạc Hà môn. (@c0306–@c0308)"},{"bridge":true,"khoang":"@c0309–@c0310","text":"Cùng VL dự đấu giá Luyện Khí Các; im lặng ngồi bên VL, khóe miệng mỉm cười. Phương thuốc lục phẩm — thứ cần để khôi phục thân thể trước khi Kết Anh — bị Chu Ngạn Hoành đoạt; VL kiên quyết tìm lại. (@c0309–@c0310)"},{"chuong":"@c0312","importance":"major","tieuDe":"Uống lục phẩm linh đan — thân thể kết tinh","text":"Tóc bạc trắng, không thể đi lại, sắp chết. Âu Dương Tử luyện thành lục phẩm linh đan. Uống vào linh lực điên cuồng tụ vào cơ thể — nhưng thân xác quá yếu, bắt đầu kết tinh. (@c0312)"},{"chuong":"@c0313","importance":"major","tieuDe":"Chết — nguyên anh đầu thai theo tranh sinh tử luân hồi","text":"Thân xác hóa xương khô. Kim đan nứt, nguyên anh xuất hiện. Vương Lâm dùng bức tranh sinh tử luân hồi mang nguyên anh nàng đầu thai vào bào thai sơn thôn, tuyên chiến thiên đạo để bảo vệ nàng. (@c0313)"},{"chuong":"@c0314","importance":"minor","tieuDe":"Chuyển sinh thành Chu Như","text":"Chuyển sinh thành bé gái Chu Như tại Hạnh Hoa Thôn, thân thể yếu ớt, mất ký ức nhưng cảm nhận tình cảm vẫn còn. (@c0314)"},{"importance":"normal","chuong":"@c0379","tieuDe":"Nguyên Anh khôi phục thần trí, chủ động chậm sinh trưởng để bảo toàn Chu Như","text":"Nguyên Anh Lý Mộ Uyển trong cơ thể Chu Như đã khôi phục một ít thần trí, biết rõ sự tình nên chủ động chậm lại quá trình sinh trưởng, không muốn hi sinh một hài tử để mình thức tỉnh. Vương Lâm dùng linh lực ngăn cản, buộc Nguyên Anh tiếp tục trưởng thành, đồng thời hứa với nàng sẽ bảo vệ hài tử, không để Chu Như bị thương tổn.","anchor":"Lý Mộ Uyển đã khôi phục một ít thần trí, biết hết sự việc","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"major","chuong":"@c0380","tieuDe":"Nguyên Anh cắn nuốt hồn phách Chu Như, thiên đạo giáng xuống truy bắt","text":"Nguyên Anh của Lý Mộ Uyển bắt đầu cắn nuốt hồn phách Chu Như trong tháng cuối cùng khi nàng ngủ sâu không tỉnh. Nguyên Anh đang dần thức tỉnh, nhưng do hồn phách Chu Như bị cắn nuốt khiến thân thể không còn hồn phách che lấp, Nguyên Anh hoàn toàn bại lộ trước thiên đạo. Sứ giả thiên đạo luân hồi lập tức giáng lâm Nguyệt tinh, vươn cánh tay chụp xuống nhằm mang Nguyên Anh của Lý Mộ Uyển đi.","anchor":"Nguyên Anh Lý Mộ Uyển bắt đầu cắn nuốt","mucCt":"vua","nguon":["bồi-cuối-quyển"]},{"importance":"major","chuong":"@c0381","tieuDe":"Thức tỉnh rồi từ bỏ – tự đẩy Nguyên Anh ra để cứu Chu Như","text":"Sau chín mươi năm im lặng, Lý Mộ Uyển thức tỉnh bên trong thân thể Chu Như, nhưng từ chối cắn nuốt hồn phách đứa bé để đổi lấy sự sống cho mình. Nàng nói với Vương Lâm rằng huynh đã gạt muội, rằng Uyển nhi muốn gặp huynh nhưng nàng vốn là người chết, không đành lòng tàn nhẫn với đứa nhỏ mà nàng xem như con mình suốt chín mươi năm. Nàng chủ động dùng Nguyên Anh chi lực chấn hồn phách Chu Như ra khỏi thân thể, khiến Nguyên Anh bản thân bộc lộ dưới thiên đạo và bắt đầu tan vỡ. Trước khi biến mất, nàng dặn Vương Lâm chăm sóc tốt bản thân và đừng làm khó Chu Như, rồi được Vương Lâm thu vào hạt châu Thiên Nghịch.","anchor":"Vương Lâm… Huynh gạt muội","mucCt":"ky","nguon":["bồi-cuối-quyển"]}],"tuVi":"Ban đầu Trúc Cơ trung kỳ (@c0124); sau hơn 100 năm đạt Kết Đan hậu kỳ nhưng 3 lần Kết Anh đều thất bại; tuổi thọ vượt giới hạn Kết Đan nhờ đan dược nhưng sắp cạn (@c0302).","tuViMoc":[{"chuong":"@c0124","canhGioi":"Trúc Cơ trung kỳ","text":"Tu vi Trúc Cơ trung kỳ; giá trị nằm ở tài luyện đan-trận chứ không ở chiến lực."},{"chuong":"@c0302","canhGioi":"Kết Đan hậu kỳ (bế tắc)","text":"Sau hơn 100 năm đạt Kết Đan hậu kỳ nhưng 3 lần thử Kết Anh đều thất bại; lần cuối (30 năm trước) suýt chết. Tuổi thọ sắp cạn, tử khí đầy thân."}],"nhanMach":[{"ten":"Vương Lâm","gap":"@c0123","quanHe":"Người yêu — ân nhân cứu mạng","ghiChu":"Cứu mạng nàng, nắm bản mệnh tinh huyết; nàng làm lò luyện đan cho hắn. Sau bốn năm, VL trả tinh huyết và chia tay (@c0137). Hơn 100 năm sau VL trở về cứu nàng khỏi Triển Bạch, hứa ở lại giúp nàng Kết Anh (@c0306).","tag":"an-nhan","uuTien":95},{"ten":"Lý Kỳ Khánh","gap":"@c0123","quanHe":"Ca ca","ghiChu":"Đệ tử Lạc Hà Môn, từng bảo vệ nàng; kể cho nàng về đại đội thứ mười của Hỏa Phần quốc.","tag":"ho-hang"},{"ten":"Liễu Phỉ","gap":"@c0303","quanHe":"Tùy tùng trung thành","ghiChu":"Bị nàng nắm hồn huyết nhưng chưa từng bị áp chế; đối xử như vãn bối; ở lại bên nàng qua khủng hoảng Triển Bạch.","tag":"thuoc-ha"},{"ten":"Tống Thanh","gap":"@c0303","quanHe":"Tùy tùng trung thành","ghiChu":"Tùy tùng lâu năm, đề xuất cầu viện Cự Ma tộc khi tình thế nguy cấp.","tag":"thuoc-ha"}],"tuiDo":{"phapBao":[{"ten":"Đan lô tùy thân (nhị phẩm)","moTa":"Lô luyện đan mang theo, đủ cho đan thường nhưng không đủ luyện Thiên Ly đan an toàn.","nguon":"@c0124, @c0126"}],"congPhap":[],"danDuoc":[{"ten":"Thiên Ly đan (bán thành phẩm)","moTa":"Một viên bán thành phẩm nàng giữ; Lạc Hà Môn chỉ làm bán thành phẩm, tế luyện nửa canh giờ là hoàn thiện, phải dùng trong một năm.","nguon":"@c0123"},{"ten":"Phương thuốc ngũ phẩm linh đan","moTa":"VL tặng; có thể dùng lò luyện đan mang theo để thử luyện.","nguon":"@c0307"}],"linhThu":[],"khac":[]}},"nguon":["@c0123","@c0124","@c0125","@c0126","@c0127","@c0128","@c0129","@c0130","@c0135","@c0136","@c0137","@c0147","@c0149","@c0302","@c0303","@c0304","@c0305","@c0306","@c0307","@c0308","@c0309","@c0310","@c0311","@c0312","@c0313","@c0314","@c0318"]},{"id":"tang-moc-nhai","name":"Tang Mộc Nhai","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Đấu Tà phái"],"canhGioiCaoNhat":"Ngưng Khí kỳ tầng mười lăm (@c0124)","trangThai":"song (linh hồn bị phong ấn)","vaiTro":"Nguồn tin / thuộc hạ bị thu phục","tinhCach":"Tà dị, giảo hoạt, vong ân bội nghĩa — sở trường dùng độc; gặp kẻ mạnh hơn lập tức đổi mặt quy phục.","blurb":"Đệ tử Đấu Tà phái lớn lên trong Tu Ma Hải, luyện song ma chi nhãn, chuyên dùng độc. Đã hạ độc giết sư huynh để 'đoạt cơ' (được sư phụ đồng ý) thì gặp Vương Lâm; bị trấn áp, linh hồn phong ấn trong Diện Hồn kỳ làm nguồn tin về Tu Ma Hải.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0124","importance":"normal","text":"Dùng độc cốt (làm từ xương Nha Huyền thú) và mười sáu loại kịch độc giết sư huynh để đoạt cơ; vừa định mang xác đi thì gặp Vương Lâm, khiếp sợ trước cảnh giới của hắn nên quy phục, ném thú cốt."},{"chuong":"@c0125","importance":"normal","text":"Bị Vương Lâm phong ấn linh hồn vào Diện Hồn kỳ; khai báo tin tức về Tu Ma Hải, Đấu Tà phái, Thi Cốc và chỉ đường cho Vương Lâm."}],"tuVi":"Ngưng Khí kỳ tầng mười lăm (@c0124).","tuViMoc":[{"chuong":"@c0124","canhGioi":"Ngưng Khí kỳ tầng mười lăm","text":"Tu vi tầng mười lăm Ngưng Khí khi gặp Vương Lâm."}],"nhanMach":[{"ten":"Lưu Sâm","quanHe":"Sư tổ","ghiChu":"Chưởng môn Đấu Tà phái (Kết Đan trung kỳ đỉnh phong).","tag":"su-mon"},{"ten":"Vương Lâm","quanHe":"Người trấn áp","ghiChu":"Trấn áp và phong ấn linh hồn hắn làm nguồn tin.","tag":"doi-thu"}],"tuiDo":{"phapBao":[{"ten":"Độc cốt (xương Nha Huyền thú)","moTa":"Đoạn thú cốt đen thổi ra khói độc; hữu hiệu với Trúc Cơ kỳ, gần vô dụng với Kết Đan kỳ. Cuối cùng ném cho Vương Lâm.","nguon":"@c0124, @c0125"}],"congPhap":[{"ten":"Song ma chi nhãn","moTa":"Cặp mắt ma luyện được, giúp cảm nhận sự lãnh khốc của đại ma.","nguon":"@c0124"}],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0124","@c0125","@c0126"]},{"id":"truong-tu-luc","name":"Trương Tự Lực","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Tà Ma Tông","Hỏa Phần Minh"],"canhGioiCaoNhat":"Nguyên Anh kỳ (@c0121)","trangThai":"song","vaiTro":"Nhân vật phụ (đội trưởng)","tinhCach":"Kiêu ngạo, khinh thường thuộc hạ; bất mãn với vị trí được phân.","blurb":"Tu sĩ Nguyên Anh kỳ của Tà Ma Tông, đội trưởng tiểu đội tám trong đại đội thứ mười của Hỏa Phần Minh. Khinh thường thuộc hạ, chỉ coi trọng năm Trúc Cơ kỳ; kinh ngạc và kiêng kỵ trước sức mạnh Vương Lâm.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0121","importance":"minor","text":"Dẫn tiểu đội tám chống đỡ tu sĩ Tuyên Vũ quốc; bị tám người lập kiếm trận vây khốn. Chứng kiến Vương Lâm chớp mắt giết bảy Trúc Cơ kỳ thì kinh nghi, đoán hắn ẩn tàng tu vi; cuối cùng quay đầu chạy khi thấy trăm kiếm quang kéo tới."}],"tuVi":"Nguyên Anh kỳ (@c0121).","tuViMoc":[{"chuong":"@c0121","canhGioi":"Nguyên Anh kỳ","text":"Đội trưởng Nguyên Anh kỳ của tiểu đội tám."}],"nhanMach":[],"tuiDo":{"phapBao":[{"ten":"Kim đan (bản mệnh)","moTa":"Viên kim đan linh khí nồng đậm ấn xuất từ ngực, điều khiển phá không đánh trúng địch.","nguon":"@c0121"}],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0121"]},{"id":"luu-sam","name":"Lưu Sâm","cn":"","aliases":[],"gioiTinh":"nam","theLuc":["Đấu Tà phái"],"canhGioiCaoNhat":"Kết Đan trung kỳ đỉnh phong (@c0125)","trangThai":"song","vaiTro":"Chưởng môn Đấu Tà phái","tinhCach":"Chưa khắc họa trực tiếp (mới nhắc tên).","blurb":"Chưởng môn Đấu Tà phái, sư tổ của Tang Mộc Nhai, tu vi Kết Đan trung kỳ đỉnh phong, có chút danh khí ở Tu Ma Hải. Tới chương 130 mới được nhắc qua lời khai, chưa xuất hiện trực tiếp.","tabs":{"diem":[],"kinhLich":[{"chuong":"@c0125","importance":"minor","text":"Được nhắc tới là người tu vi cao nhất Đấu Tà phái (Kết Đan trung kỳ đỉnh phong), sư tổ Tang Mộc Nhai."}],"tuVi":"Kết Đan trung kỳ đỉnh phong (@c0125).","tuViMoc":[{"chuong":"@c0125","canhGioi":"Kết Đan trung kỳ đỉnh phong","text":"Tu vi cao nhất Đấu Tà phái theo lời khai."}],"nhanMach":[],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0125","@c0129"]},{"id":"ma-dau-long-can","name":"Ma đầu (Long Cân)","cn":"","aliases":["Ma đầu trú thể Long Cân"],"gioiTinh":"nam","theLuc":[],"canhGioiCaoNhat":"Kết Đan kỳ (@c0134)","trangThai":"song (bị Vương Lâm khống chế; trú thể là Long Cân)","vaiTro":"Pháp khí linh thể do Vương Lâm tạo, trú thể trong Long Cân","tinhCach":"Xảo quyệt, giỏi che giấu; bí mật đột phá và khôi phục trí nhớ mà không lộ; chỉ bại lộ khi bị áp chế","blurb":"Ma đầu do Vương Lâm tạo ra từ nguyên thần của Hứa Lập Quốc ở mức Trúc Cơ hậu kỳ đỉnh, sau được chuyển trú vào Long Cân. Trong thời gian ở trong Long Cân, y bí mật đột phá lên Kết Đan kỳ và khôi phục trí nhớ, che giấu cả hai điều này cho đến khi bị Vương Lâm phát hiện và ép buộc khai báo, nhả linh hồn tích lũy.","tabs":{"diem":[{"text":"Được Vương Lâm tạo ra từ nguyên thần Hứa Lập Quốc, hủy ý thức và ép ăn hồn dã thú","chuong":"@c0112"},{"text":"Được ký thân vào phi kiếm đen của Vương Lâm","chuong":"@c0117"},{"text":"Chuyển trú thể sang Long Cân theo lệnh Vương Lâm","chuong":"@c0127"},{"text":"Bí mật đột phá Kết Đan kỳ và khôi phục trí nhớ trong Long Cân, che giấu đến khi bị phát hiện","chuong":"@c0134"},{"text":"Bị Vương Lâm ép nhả 43 linh hồn tích lũy để gia cường thần thức","chuong":"@c0135"}],"kinhLich":[{"chuong":"@c0112","importance":"normal","text":"Được Vương Lâm tạo ra: bắt sống Hứa Lập Quốc, hủy ý thức, ép nguyên thần ăn hồn dã thú đến khi hào quang ám hồng hình thành — Ma Đầu Trúc Cơ hậu kỳ đỉnh giả đan. Lưu trong Thiết Phiến."},{"chuong":"@c0117","importance":"minor","text":"Được ký thân vào phi kiếm đen mới của Vương Lâm."},{"chuong":"@c0127","importance":"normal","text":"Chuyển trú thể sang Long Cân (gân giao long tế luyện) theo lệnh Vương Lâm."},{"chuong":"@c0134","importance":"major","text":"Bị Vương Lâm phát hiện đã đột phá Kết Đan kỳ và khôi phục trí nhớ — hai bí mật che giấu lâu nay bị lộ. Bị áp chế bằng thôn hồn, buộc nhả hồn phách."},{"chuong":"@c0135","importance":"normal","text":"Bị Vương Lâm ép nhả 43 linh hồn tích lũy; VL dùng Cực cảnh thần thức nuốt để gia cường thần thức."}],"tuVi":"Ban đầu Trúc Cơ hậu kỳ đỉnh giả đan; bí mật đột phá lên Kết Đan kỳ trong Long Cân (@c0134).","tuViMoc":[{"chuong":"@c0112","canhGioi":"Trúc Cơ hậu kỳ đỉnh giả đan","text":"Được tạo ra ở mức Trúc Cơ hậu kỳ đỉnh giả đan từ nguyên thần Hứa Lập Quốc."},{"chuong":"@c0134","canhGioi":"Kết Đan kỳ","text":"Đột phá Kết Đan kỳ trong Long Cân — bị Vương Lâm phát hiện và áp chế."}],"nhanMach":[{"ten":"Vương Lâm","quanHe":"Chủ tạo ra / khống chế","ghiChu":"Tạo ra từ Hứa Lập Quốc, dùng làm pháp khí linh thể trú trong Long Cân.","tag":"su-mon"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0112","@c0117","@c0127","@c0134","@c0135"]},{"id":"tuc-mac-lao-nhan","name":"Tức Mặc lão nhân","cn":"","aliases":["Tức Mặc đại tiên"],"gioiTinh":"nam","theLuc":["Tán tu (hoành hành Triệu quốc)"],"canhGioiCaoNhat":"Nguyên Anh trung kỳ đỉnh (@c0213)","trangThai":"tu-vong (@c0213 — bị Cực Cảnh thần thức Vương Lâm giết tan)","vaiTro":"Phản diện phụ arc diệt Đằng gia — tán tu luyện chế khôi lỗi","tinhCach":"Kiêu ngạo, phô trương; chuyên luyện chế khôi lỗi và ưa vật chất phô trương; tính toán tự bảo toàn nhưng ngạo mạn hại thân","blurb":"Tán tu cảnh giới Nguyên Anh trung kỳ đỉnh, nổi danh hoành hành Triệu quốc nhờ nghề luyện chế khôi lỗi (con rối cổ thi). Ngụy trang thành hình dáng béo phệ, chỉ khi vận công kết anh mới lộ hình thật là trung niên anh tuấn. Mang mối thù cũ với Vương Lâm và cuối cùng bị Vương Lâm phóng Cực Cảnh thần thức giết tan.","tabs":{"diem":[{"text":"Tán tu đạt tới Nguyên Anh trung kỳ đỉnh, lộ hình thật sau khi vận công kết anh","chuong":"@c0213"},{"text":"Nổi danh hoành hành Triệu quốc nhờ nghề luyện chế khôi lỗi (con rối cổ thi)","chuong":"@c0213"},{"text":"Dùng xe hoa phô trương chặn đường Vương Lâm trên đường tới Hợp Hoan Tông","chuong":"@c0213"},{"text":"Sư phụ của Bạch Triển (đệ tử thứ sáu, Kết Đan kỳ), người đã bị Vương Lâm giết","chuong":"@c0068"},{"text":"Bị Vương Lâm phóng Cực Cảnh thần thức (hồng quang) giết tan, mất 4 con rối và ngọc giản luyện rối","chuong":"@c0213"}],"kinhLich":[{"chuong":"@c0213","importance":"major","text":"Xe hoa phô trương chặn đường Vương Lâm trên đường tới Hợp Hoan Tông. Nhận diện đầu Đằng Cao mà VL giơ ra, biết VL báo thù Đằng gia nên định tránh. Lộ mối thù cũ (400 năm trước VL giết tiểu đồ đệ của hắn). Kết anh lột xác thành trung niên anh tuấn tu vi thật; ngạo mạn đòi VL tự chặt một tay đổi lấy 100 năm không bị giết; khi bỏ đi thì bị VL phóng Cực Cảnh thần thức hồng quang giết tan. Mất túi trữ vật (4 con rối Nguyên Anh kỳ + ngọc giản luyện rối) bị VL thu đoạt. (@c0213)"}],"tuVi":"Nguyên Anh trung kỳ đỉnh (hình thật sau khi vận công kết anh); ngụy trang Nguyên Anh sơ kỳ bằng dáng béo phì (@c0213).","tuViMoc":[{"chuong":"@c0213","canhGioi":"Nguyên Anh trung kỳ đỉnh","text":"Lộ hình thật sau khi vận công kết anh; tu vi bị VL xác định là đỉnh Nguyên Anh trung kỳ, chỉ cách hậu kỳ một chút."}],"nhanMach":[{"ten":"Bạch Triển","quanHe":"Đệ tử thứ sáu","ghiChu":"Bạch Triển Kết Đan kỳ, tán tu tà đạo; đã bị Vương Lâm giết @c0068.","tag":"de-tu"},{"ten":"Vương Lâm","quanHe":"Kẻ thù (400 năm)","ghiChu":"VL giết tiểu đồ đệ của hắn 400 năm trước; sau đó bị VL giết tại Hợp Hoan Tông @c0213.","tag":"doi-thu"}],"tuiDo":{"phapBao":[],"congPhap":[],"danDuoc":[],"linhThu":[],"khac":[]}},"nguon":["@c0068","@c0212","@c0213"]}]};
